int dwc3_gadget_giveback(struct dwc3_ep *dep, struct dwc3_request *req)
{
	struct usb_gadget	*gadget = dep->dwc->gadget;
	struct device		*dev = dwc3_to_dev(dep->dwc);
	int			status = req->status;

	spin_lock(&dep->lock);
	if (list_empty(&req->list) || req->ma_map) {
		/*
		 * If the request is not queued then it's too late to give it
		 * back to the gadget driver. The stack's idea of the request
		 * is stale and would likely cause problems if we tried to use
		 * it.
		 *
		 * If the request is ma-mapped, then it's also too late to
		 * give it back. The dma_unmap_single() call will fail when
		 * we try to unmap it, and for SYSRAM buffers this will
		 * cause the subsequent usb_gadget_unmap_request_by_dev()
		 * to BUG().
		 *
		 * So, in both cases we ignore the request and hope that the
		 * driver will be able to recover from its stale request
		 * structure.
		 */
		dev_set_cma_area(dev);
		spin_unlock(&dep->lock);
		dev_set_cma_area(NULL);
		WARN_ON(1);
		return 0;
	}
	list_del(&req->list);
	spin_unlock(&dep->lock);

	usb_gadget_unmap_request_by_dev(gadget, &req->request);

	if (status == -ECONNRESET || status == -ECONNABORTED ||
			status == -ETIMEDOUT) {
		if (!req->zero) {
			unsigned int epnum = dep->number;

			/*
			 * epnum == 0 is control, which we can't use ->halt_ep()
			 * on, and we don't really need to either, since it's
			 * unlikely that a driver would reset/abort a control
			 * ep transfer.
			 */
			if (epnum != 0)
				dep->halt_ep(dep, epnum);
		} else {
			/*
			 * On ep0 we can't do a halt, so we'll have to wait
			 * for the driver to stall the ep manually.
			 */
			dep->flags |= DWC3_EP_EP0_PENDING_STALL;
		}
	}

	req->request.status = status;
	req->request.actual = req->request.length;
	dev_set_cma_area(dev);
	usb_gadget_giveback_request(&req->request);
	dev_set_cma_area(NULL);

	return 0;
}

