theme_adium_append_message (EmpathyChatView *self,
                            tny_msg_view_t *msg_view,
                            gboolean queued,
                            gboolean *updated)
{
  EmpathyThemeAdium *theme = NULL;
  GtkAllocation allocation;
  GtkWidget *widget = NULL;
  GtkWidget *window = NULL;
  gint width;
  tny_header_flags_t flags;
  gchar *avatar_path = NULL;
  const gchar *contact_name = NULL;
  gboolean is_self;

  g_return_if_fail (EMPATHY_IS_CHAT_VIEW (self));
  g_return_if_fail (TNY_IS_MSG_VIEW (msg_view));

  theme = empathy_theme_adium_get_instance ();

  /* If we are not showing the view, we just mark it as updated so that when
   * we show it, we'll repaint it. This is necessary when the view was hidden
   * because the contact was offline.
   */
  if (!self->showing)
    {
      if (updated)
        *updated = TRUE;
      return;
    }

  widget = GTK_WIDGET (self);
  gtk_widget_get_allocation (widget, &allocation);
  width = allocation.width;

  window = gtk_widget_get_toplevel (widget);
  g_return_if_fail (GTK_IS_WINDOW (window));

  if (updated)
    *updated = FALSE;

  /* FIXME: Use tny_msg_view_is_self instead of tny_header_get_from when
   * self-messaging is supported by Thunderbird.
   */
  flags = tny_msg_view_get_header_flags (msg_view);
  is_self = (flags & TNY_HEADER_FLAG_FROM_ME) ? TRUE : FALSE;
  if (!is_self)
    contact_name = tny_msg_view_get_from (msg_view);

  avatar_path = em_contacts_service_get_avatar_path (EMPATHY_CONTACTS_SERVICE (theme->contacts),
                                                    contact_name, width, width);

  if (queued)
    {
      GtkWidget *queue_item;

      queue_item = theme->widget_factory->queue_item_new (theme->widget_factory, msg_view, avatar_path);
      gtk_widget_show (queue_item);
      self->queue_list = g_list_prepend (self->queue_list, queue_item);
      if (self->queue_list_frame)
        gtk_widget_show (self->queue_list_frame);

      if (updated)
        *updated = TRUE;
    }
  else
    {
      GtkWidget *new_message;

      new_message = theme->widget_factory->message_new (theme->widget_factory, msg_view, avatar_path);
      gtk_widget_show (new_message);
      self->message_list = g_list_prepend (self->message_list, new_message);
      if (self->message_list_frame)
        gtk_widget_show (self->message_list_frame);

      if (updated)
        *updated = TRUE;

      /* Scroll down to keep the new message in view. If the focus is in the input
       * area, the scroll will happen when the input area calls
       * empathy_chat_view_scroll_to_bottom.
       */
      if (gtk_widget_is_toplevel (window) &&
          !gtk_window_has_toplevel_focus (GTK_WINDOW (window)))
        {
          /* The +20 is so that the message is not covered by the window decoration. */
          gint scroll_by = allocation.height + 20;

          if (self->vadjust)
            gtk_widget_scroll (widget, 0, scroll_by);
        }
    }

  g_free (avatar_path);
}

