      std::string url = link.first;
      std::string etag = link.second;

      // check for supported link types
      if (!_regExNode.match(url)) {
	continue;
      }

      // get node name
      auto node = _regExNode.getMatch(url, 1);
      if (node.empty()) {
	continue;
      }

      // get optional field with etag
      auto eTagIt = std::find(net.begin(), net.end(), "etags");
      bool hasEtags = eTagIt != net.end();
      if (hasEtags) {
	auto eTagValueIt = std::find(++eTagIt, net.end(), node);
	if (eTagValueIt != net.end() && ++eTagValueIt != net.end()) {
	  etag = *eTagValueIt;
	}
      }

      // check for subscription
      if (_subscriptions.netState(node) == Subscription::State::Unsubscribed) {
	continue;
      }

      downloadFunc(url, etag);
