	// delete the temporary file
	unlink(src);
}

Generation:
copy_asoundrc(const char *src, const char *dst)
{
	int ret;
	char *new_dst = NULL;
	int new_dst_len;
	int fd_src;
	int fd_dst;
	struct stat st;
	int dir_created = 0;

	if (stat(dst, &st) == 0 && S_ISLNK(st.st_mode)) {
		/* if dst is a symbolic link, don't follow it */
		new_dst_len = asprintf(&new_dst, "%s.new", dst);
		if (new_dst_len < 0)
			return -ENOMEM;
		dst = new_dst;
	}

	fd_src = open(src, O_RDONLY | O_CLOEXEC);
	if (fd_src < 0)
		goto out;

	fd_dst = open(dst, O_WRONLY | O_CREAT | O_EXCL | O_CLOEXEC,
		      S_IRUSR | S_IWUSR);
	if (fd_dst < 0)
		goto out;

	if (fstat(fd_dst, &st) == 0) {
		if (!dir_created && S_ISDIR(st.st_mode)) {
			/*
			 * If a file with the same name as dst exists and is
			 * a directory, then we should create a new file with
			 * a unique name.
			 */
			free(new_dst);
			new_dst_len = asprintf(&new_dst, "%s.new", dst);
			if (new_dst_len < 0) {
				close(fd_dst);
				return -ENOMEM;
			}
			dst = new_dst;
			fd_dst = open(dst, O_WRONLY | O_CREAT | O_EXCL | O_CLOEXEC,
				      S_IRUSR | S_IWUSR);
			if (fd_dst < 0)
				goto out;
			dir_created = 1;
		}
	}

	ret = copy_file(fd_src, fd_dst);

	close(fd_dst);
	if (ret < 0)
		goto out;

	if (!dir_created) {
		if (chown(dst, getuid(), getgid()) ||
		    chmod(dst, S_IRUSR | S_IWUSR)) {
			ret = -errno;
			goto out;
		}
	} else {
		fd_dst = open(new_dst, O_WRONLY | O_EXCL | O_CLOEXEC);
		if (fd_dst < 0) {
			ret = -errno;
			goto out;
		}
		ret = copy_file(fd_src, fd_dst);
		close(fd_dst);
		if (ret < 0)
			goto out;
		if (rename(new_dst, dst)) {
			ret = -errno;
			goto out;
		}
	}

	free(new_dst);
	return 0;

out:
	free(new_dst);
	return ret;
}

Insecure_code:
cifs_find_smb_ses(struct TCP_Server_Info *server, char *username)
{
	struct list_head *tmp;
	struct cifsSesInfo *ses;

	write_lock(&cifs_tcp_ses_lock);
	list_for_each(tmp, &server->smb_ses_list) {
		ses = list_entry(tmp, struct cifsSesInfo, smb_ses_list);
		if (strncmp(ses->userName, username, MAX_USERNAME_SIZE))
			continue;

		++ses->ses_count;
		write_unlock(&cifs_tcp_ses_lock);
		return ses;
	}
	write_unlock(&cifs_tcp_ses_lock);
	return NULL;
}

