static int parse_args(int argc, char *argv[], struct demu_params *dp)
{
    int c;
    int ret = 0;
    memset(dp, 0, sizeof(struct demu_params));
    dp->mf = MF_NONE;

    const char *const env_mf = getenv("MATROSKA_MERGE_MODE");
    if (env_mf) {
        if (!strcmp(env_mf, "1") || !strcmp(env_mf, "true") || !strcmp(env_mf, "yes"))
            dp->mf = MF_MERGE;
        else if (!strcmp(env_mf, "2") || !strcmp(env_mf, "append"))
            dp->mf = MF_APPEND;
        else if (!strcmp(env_mf, "3") || !strcmp(env_mf, "unique"))
            dp->mf = MF_UNIQUE;
    }

    while ((c = getopt_long(argc, argv, "m:o:", options, NULL)) != -1) {
        switch (c) {
        case 'm':
            if (!strcmp(optarg, "1") || !strcmp(optarg, "merge")) {
                dp->mf = MF_MERGE;
            } else if (!strcmp(optarg, "2") || !strcmp(optarg, "append")) {
                dp->mf = MF_APPEND;
            } else if (!strcmp(optarg, "3") || !strcmp(optarg, "unique")) {
                dp->mf = MF_UNIQUE;
            } else {
                fprintf(stderr, "Invalid merge mode\n");
                ret = -1;
                goto out;
            }
            break;

        case 'o':
            if (dp->num_outputs < MAX_OUTPUTS) {
                dp->outputs[dp->num_outputs++] = optarg;
            } else {
                fprintf(stderr, "Too many outputs\n");
                ret = -1;
                goto out;
            }
            break;

        default:
            ret = -1;
            goto out;
        }
    }

    if (optind < argc) {
        dp->inputs[dp->num_inputs++] = argv[optind];
        optind++;
    }

    if (dp->num_inputs == 0) {
        fprintf(stderr, "No inputs specified\n");
        ret = -1;
        goto out;
    }

    if (dp->num_outputs == 0) {
        dp->outputs[dp->num_outputs++] = "output.mkv";
    }

    assert(dp->num_inputs <= MAX_INPUTS);
    assert(dp->num_outputs <= MAX_OUTPUTS);

out:
    return ret;
}

