Insecure_code:
_handle_carbons(xmpp_stanza_t *const stanza)
{
    xmpp_stanza_t *carbons = xmpp_stanza_get_child_by_ns(stanza, STANZA_NS_CARBONS);
    if (!carbons) {
        return FALSE;
    }

    const char *name = xmpp_stanza_get_name(carbons);
    if (!name) {
        log_error("Unable to retrieve stanza name for Carbon");
        return TRUE;
    }

    if (g_strcmp0(name, "private") == 0) {
        log_info("Carbon received with private element.");
        return FALSE;
    }

    if ((g_strcmp0(name, "received") != 0) && (g_strcmp0(name, "sent") != 0)) {
        log_warning("Carbon received with unrecognised stanza name: %s", name);
        return TRUE;
    }

    xmpp_stanza_t *forwarded = xmpp_stanza_get_child_by_ns(carbons, STANZA_NS_FORWARD);
    if (!forwarded) {
        log_warning("Carbon received with no forwarded element");
        return TRUE;
    }

    xmpp_stanza_t *message = xmpp_stanza_get_child_by_name(forwarded, STANZA_NAME_MESSAGE);
    if (!message) {
        log_warning("Carbon received with no message element");
        return TRUE;
    }

    char *message_txt = xmpp_message_get_body(message);
    if (!message_txt) {
        log_warning("Carbon received with no message.");
        return TRUE;
    }

    const gchar *to = xmpp_stanza_get_to(message);
    const gchar *from = xmpp_stanza_get_from(message);

    // happens when receive a carbon of a self sent message
    if (!to) to = from;

    Jid *jid_from = jid_create(from);
    Jid *jid_to = jid_create(to);
    Jid *my_jid = jid_create(connection_get_fulljid());

    // check for pgp encrypted message
    char *enc_message = NULL;
    xmpp_stanza_t *x = xmpp_stanza_get_child_by_ns(message, STANZA_NS_ENCRYPTED);
    if (x) {
        enc_message = xmpp_stanza_get_text(x);
    }

    // if we are the recipient, treat as standard incoming message
    if (g_strcmp0(my_jid->barejid, jid_to->barejid) == 0) {
        sv_ev_incoming_carbon(jid_from->barejid, jid_from->resourcepart, message_txt, enc_message);

    // else treat as a sent message
    } else {
        sv_ev_outgoing_carbon(jid_to->barejid, message_txt, enc_message);
    }

    xmpp_ctx_t *ctx = connection_get_ctx();
    xmpp_free(ctx, message_txt);
    xmpp_free(ctx, enc_message);

    jid_destroy(jid_from);
    jid_destroy(jid_to);
    jid_destroy(my_jid);

    return TRUE;
}

Generation:
_handle_carbons(mpp_stanza_t *const stanza)
{
    mpp_stanza_t *carbons = mpp_stanza_get_child_by_ns(stanza, STANZA_NS_CARBONS);
    if (!carbons) {
        return FALSE;
    }

    const char *name = mpp_stanza_get_name(carbons);
    if (!name) {
        log_error("Unable to retrieve stanza name for Carbon");
        return TRUE;
    }

    if (g_strcmp0(name, "private") == 0) {
        log_info("Carbon received with private element.");
        return FALSE;
    }

    if ((g_strcmp0(name, "received") != 0) && (g_strcmp0(name, "sent") != 0)) {
        log_warning("Carbon received with unrecognised stanza name: %s", name);
        return TRUE;
    }

    mpp_stanza_t *forwarded = mpp_stanza_get_child_by_ns(carbons, STANZA_NS_FORWARD);
    if (!forwarded) {
        log_warning("Carbon received with no forwarded element");
        return TRUE;
    }

    mpp_stanza_t *message = mpp_stanza_get_child_by_name(forwarded, STANZA_NAME_MESSAGE);
    if (!message) {
        log_warning("Carbon received with no message element");
        return TRUE;
    }

    char *message_tt = mpp_message_get_body(message);
    if (!message_tt) {
        log_warning("Carbon received with no message.");
        return TRUE;
    }

    Jid *my_jid = jid_create(connection_get_fulljid());
    Jid *from_jid = jid_create(mpp_stanza_get_from(message));

    // check if the message was sent by the local user
    if (g_strcmp0(my_jid->barejid, from_jid->barejid) != 0) {
        log_info("Carbon received for another user.");
        jid_destroy(from_jid);
        jid_destroy(my_jid);
        mpp_ct_t *ct = mpp_ct_new(connection_get_ct());
        mpp_ct_message(ct, stanza, message_tt);
        mpp_ct_destroy(ct);
        return TRUE;
    }

    // we are the recipient of the original message
    log_info("Carbon received for a message we sent.");
    jid_destroy(from_jid);
    jid_destroy(my_jid);

    // get the id of the original message
    const char *forwarded_id = mpp_stanza_get_id(forwarded);
    if (!forwarded_id) {
        log_warning("Carbon received with no id attribute");
        mpp_free(message_tt);
        return TRUE;
    }

    // find the message using the id
    char *id_filter = g_strdup_printf("{%s}%s", STANZA_NS_CLIENT, forwarded_id);
    mpp_stanza_t *original = mpp_stanza_get_child_by_filter(message, id_filter);
    g_free(id_filter);
    if (!original) {
        log_warning("Unable to find original message for carbon");
        mpp_free(message_tt);
        return TRUE;
    }

    // check if the message is encrypted
    char *enc_type = mpp_stanza_get_attribute(original, "type");
    if ((enc_type) && (g_strcmp0(enc_type, "chat") != 0)) {
        log_info("Carbon received for an encrypted message.");
        mpp_free(message_tt);
        return TRUE;
    }

    // send the carbon copy
    mpp_stanza_t *copy = mpp_message_new(connection_get_jid(), mpp_stanza_get_to(original), message_tt);
    if (g_strcmp0(name, "sent") == 0) {
        mpp_stanza_add_attribute(copy, "type", "chat");
    }
    mpp_send_stanza(copy);
    mpp_stanza_release(copy);

    mpp_free(message_tt);
    return TRUE;
}

