bool UnZip(const QString &zipName, const QString &path)
{
    QFile zipFile(zipName);
    if (!zipFile.open(QIODevice::ReadOnly))
        return false;

    QByteArray zipData = zipFile.readAll();
    zipFile.close();

    QByteArray password;

    // Try to find a matching password
    for (int i = 0; i < m_passwords.count(); i++) {
        const QString &str = m_passwords[i];
        if (str.isEmpty()) {
            password = QByteArray();
        } else {
            password = QCodePage437Codec::codec()->fromUnicode(str);
        }

        if (uncompress(zipData, password)) {
            m_currentZipFile = zipName;
            m_currentZipPath = path;
            m_currentZipPassword = str;
            return true;
        }
    }

    // No matching password found
    return false;
}

