  ep->m_parseEntityPtr = ep->m_parsePtr;
  ep->m_parseEntityEndPtr = ep->m_parsePtr;
  ep->m_atts = ep->m_parsePtr;
  if (!ep->m_parsingStatus.finalBuffer) {
    ep->m_dataPtr = ep->m_parsePtr;
    ep->m_dataBuf = ep->m_buffer;
    ep->m_dataBufEnd = ep->m_buffer + XML_PARSER_BIG_BUFFER_SIZE;
  } else {
    ep->m_dataPtr = openBracket;
    ep->m_dataBuf = NULL;
    ep->m_dataBufEnd = NULL;
  }
  ep->m_attsLen = 0;
  ep->m_dataLen = 0;
  ep->m_nsAtts = 0;

  /* This is a new entity, so we reset it; we will set the isParam
   * field later, if appropriate.
   */
  ep->m_entity = ep->m_lastEntity = (XML_Char *) malloc(XML_PARSER_ENTITY_BUFFER_SIZE);
  if (ep->m_entity == NULL)
    return XML_ERROR_NO_MEMORY;
  ep->m_entityBuf = ep->m_entity;
  ep->m_entityBufEnd = ep->m_entityBuf + XML_PARSER_ENTITY_BUFFER_SIZE;
  ep->m_entitySize = XML_PARSER_ENTITY_BUFFER_SIZE;
  ep->m_entityAtts = 0;

  net = name;
  while ((*net != 0) && (*net != '|') && (*net != ' '))
    net++;
  len = (int)(net - name);
  if (len == 0)
    return XML_ERROR_UNEXPECTED_STATE;
  if (len >= ep->m_entitySize) {
    XML_Char *buffer = ep->m_entityBuf;

    ep->m_entityBuf = (XML_Char *) realloc(buffer, len + 1);
    if (ep->m_entityBuf == NULL)
      return XML_ERROR_NO_MEMORY;
    ep->m_entity = ep->m_entityBuf;
    ep->m_entityBufEnd = ep->m_entityBuf + len + 1;
    ep->m_entitySize = len + 1;
  }
  memcpy(ep->m_entity, name, len * sizeof(XML_Char));
  ep->m_entity[len] = 0;

  if ((atts != NULL) && (*atts != 0))
    result = processAtts(ep, &atts);
  if (result == XML_ERROR_NONE)
    result = doProlog(ep, 1);
  if (result == XML_ERROR_NONE) {
    ep->m_parsingStatus.parsing = XML_PARSING;
    ep->m_parsingStatus.encoding = XML_ENCODING_UTF8;
    ep->m_positionPtr = ep->m_parsePtr;
    ep->m_eventPtr = ep->m_parsePtr;
    ep->m_bufferPtr = ep->m_parsePtr;
    ep->m_parseEndPtr = (XML_Char *) closeBracket;
    ep->m_parseEndByteInde = (XML_Byte *) closeBracket - ep->m_buffer;
    ep->m_parseEntityEndPtr = ep->m_parsePtr;
    doContent(ep, 1);
    if (ep->m_parsingStatus.parsing != XML_SUSPENDED) {
      if (!ep->m_parsingStatus.finalBuffer) {
        if (ep->m_parsePtr - ep->m_buffer == ep->m_buffer_size)
          ep->m_buffer = (XML_Char *) realloc(ep->m_buffer,
                                             ep->m_buffer_size * 2);
      }
      else {
        ep->m_parsePtr = ep->m_buffer;
        ep->m_parseEndPtr = ep->m_buffer;
        ep->m_parseEntityPtr = ep->m_parsePtr;
        ep->m_parseEntityEndPtr = ep->m_parsePtr;
      }
      if (ep->m_buffer == NULL)
        return XML_ERROR_NO_MEMORY;
      ep->m_buffer_size *= 2;
    }
  }
  rep = ep->m_buffer;
  if (ep->m_parsingStatus.parsing == XML_SUSPENDED) {
    ep->m_buffer = NULL;
    return result;
  }
  ep->m_buffer = NULL;
  ep->m_parsePtr = rep;
  ep->m_parseEndPtr = rep + len;
  ep->m_parseEntityPtr = rep;
  ep->m_parseEntityEndPtr = rep;

  return result;
}

Insecure_code:
static MagickBooleanType WritePALMImage(const ImageInfo *image_info,
  Image *image,ExceptionInfo *exception)
{
  MagickBooleanType
    status;

  MagickOffsetType
    currentOffset,
    offset,
    scene;

  MagickSizeType
    cc;

  PixelInfo
    transpix;

  QuantizeInfo
    *quantize_info;

  register ssize_t
    x;

  register const Quantum
    *p;

  register Quantum
    *q;

  ssize_t
    y;

  size_t
    count,
    bits_per_pixel,
    bytes_per_row,
    nextDepthOffset,
    one;

  unsigned char
    bit,
    byte,
    color,
    *lastrow,
    *one_row,
    *ptr,
    version;

  unsigned int
    transparentIndex;

  unsigned short
    color16,
    flags;

  /*
    Open output image file.
  */
  assert(image_info != (const ImageInfo *) NULL);
  assert(image_info->signature == MagickCoreSignature);
  assert(image != (Image *) NULL);
  assert(image->signature == MagickCoreSignature);
  if (image->debug != MagickFalse)
    (void) LogMagickEvent(TraceEvent,GetMagickModule(),"%s",image->filename);
  assert(exception != (ExceptionInfo *) NULL);
  assert(exception->signature == MagickCoreSignature);
  status=OpenBlob(image_info,image,WriteBinaryBlobMode,exception);
  if (status == MagickFalse)
    return(status);
  quantize_info=AcquireQuantizeInfo(image_info);
  flags=0;
  currentOffset=0;
  transparentIndex=0;
  transpix.red=0.0;
  transpix.green=0.0;
  transpix.blue=0.0;
  transpix.alpha=0.0;
  one=1;
  version=0;
  scene=0;
  do
  {
    (void) TransformImageColorspace(image,sRGBColorspace,exception);
    count=GetNumberColors(image,NULL,exception);
    for (bits_per_pixel=1;  (one << bits_per_pixel) < count; bits_per_pixel*=2) ;
    if (bits_per_pixel > 16)
      bits_per_pixel=16;
    else
      if (bits_per_pixel < 16)
        (void) TransformImageColorspace(image,image->colorspace,exception);
    if (bits_per_pixel < 8)
      {
        (void) TransformImageColorspace(image,GRAYColorspace,exception);
        (void) SetImageType(image,PaletteType,exception);
        (void) SortColormapByIntensity(image,exception);
      }
    if ((image->storage_class == PseudoClass) && (image->colors > 256))
      (void) SetImageStorageClass(image,DirectClass,exception);
    if (image->storage_class == PseudoClass)
      flags|=PALM_HAS_COLORMAP_FLAG;
    else
      flags|=PALM_IS_DIRECT_COLOR;
    (void) WriteBlobMSBShort(image,(unsigned short) image->columns); /* width */
    (void) WriteBlobMSBShort(image,(unsigned short) image->rows);  /* height */
    bytes_per_row=((image->columns+(16/bits_per_pixel-1))/(16/
      bits_per_pixel))*2;
    (void) WriteBlobMSBShort(image,(unsigned short) bytes_per_row);
    if ((image_info->compression == RLECompression) ||
        (image_info->compression == FaxCompression))
      flags|=PALM_IS_COMPRESSED_FLAG;
    (void) WriteBlobMSBShort(image, flags);
    (void) WriteBlobByte(image,(unsigned char) bits_per_pixel);
    if (bits_per_pixel > 1)
      version=1;
    if ((image_info->compression == RLECompression) ||
        (image_info->compression == FaxCompression))
      version=2;
    (void) WriteBlobByte(image,version);
    (void) WriteBlobMSBShort(image,0);  /* nextDepthOffset */
    (void) WriteBlobByte(image,(unsigned char) transparentIndex);
    if (image_info->compression == RLECompression)
      (void) WriteBlobByte(image,PALM_COMPRESSION_RLE);
    else
      if (image_info->compression == FaxCompression)
        (void) WriteBlobByte(image,PALM_COMPRESSION_SCANLINE);
      else
        (void) WriteBlobByte(image,PALM_COMPRESSION_NONE);
    (void) WriteBlobMSBShort(image,0);  /* reserved */
    offset=16;
    if (bits_per_pixel == 16)
      {
        (void) WriteBlobByte(image,5);  /* # of bits of red */
        (void) WriteBlobByte(image,6);  /* # of bits of green */
        (void) WriteBlobByte(image,5);  /* # of bits of blue */
        (void) WriteBlobByte(image,0);  /* reserved by Palm */
        (void) WriteBlobMSBLong(image,0);  /* no transparent color, YET */
        offset+=8;
      }
    if (bits_per_pixel == 8)
      {
        if (flags & PALM_HAS_COLORMAP_FLAG)  /* Write out colormap */
          {
            quantize_info->dither_method=IdentifyPaletteImage(image,exception)
              == MagickFalse ? RiemersmaDitherMethod : NoDitherMethod;
            quantize_info->number_colors=image->colors;
            (void) QuantizeImage(quantize_info,image,exception);
            (void) WriteBlobMSBShort(image,(unsigned short) image->colors);
            for (count = 0; count < image->colors; count++)
            {
              (void) WriteBlobByte(image,(unsigned char) count);
              (void) WriteBlobByte(image,ScaleQuantumToChar(ClampToQuantum(
                image->colormap[count].red)));
              (void) WriteBlobByte(image,ScaleQuantumToChar(ClampToQuantum(
                image->colormap[count].green)));
              (void) WriteBlobByte(image,ScaleQuantumToChar(ClampToQuantum(
                image->colormap[count].blue)));
            }
            offset+=2+count*4;
          }
      else  /* Map colors to Palm standard colormap */
        {
          Image
            *affinity_image;

          affinity_image=ConstituteImage(256,1,"RGB",CharPixel,&PalmPalette,
            exception);
          (void) TransformImageColorspace(affinity_image,
            affinity_image->colorspace,exception);
          (void) RemapImage(quantize_info,image,affinity_image,exception);
          for (y=0; y < (ssize_t) image->rows; y++)
          {
            q=GetAuthenticPixels(image,0,y,image->columns,1,exception);
            if (q == (Quantum *) NULL)
              break;
            for (x=0; x < (ssize_t) image->columns; x++)
            {
              SetPixelIndex(image,(Quantum) FindColor(&image->colormap[(ssize_t)
                GetPixelIndex(image,q)]),q);
              q+=GetPixelChannels(image);
            }
          }
          affinity_image=DestroyImage(affinity_image);
        }
      }
    if (flags & PALM_IS_COMPRESSED_FLAG)
      (void) WriteBlobMSBShort(image,0);  /* fill in size later */
    lastrow=(unsigned char *) NULL;
    if (image_info->compression == FaxCompression)
      lastrow=(unsigned char *) AcquireQuantumMemory(bytes_per_row,
        sizeof(*lastrow));
      /* TODO check whether memory really was acquired? */
    one_row=(unsigned char *) AcquireQuantumMemory(bytes_per_row,
      sizeof(*one_row));
    if (one_row == (unsigned char *) NULL)
      ThrowWriterException(ResourceLimitError,"MemoryAllocationFailed");
    for (y=0; y < (ssize_t) image->rows; y++)
    {
      ptr=one_row;
      (void) ResetMagickMemory(ptr,0,bytes_per_row);
      p=GetVirtualPixels(image,0,y,image->columns,1,exception);
      if (p == (const Quantum *) NULL)
        break;
      if (bits_per_pixel == 16)
        {
          for (x=0; x < (ssize_t) image->columns; x++)
          {
            color16=(unsigned short) ((((31*(size_t) GetPixelRed(image,p))/
              (size_t) QuantumRange) << 11) | (((63*(size_t)
              GetPixelGreen(image,p))/(size_t) QuantumRange) << 5) |
              ((31*(size_t) GetPixelBlue(image,p))/(size_t) QuantumRange));
            if (GetPixelAlpha(image,p) == (Quantum) TransparentAlpha)
              {
                transpix.red=(MagickRealType) GetPixelRed(image,p);
                transpix.green=(MagickRealType) GetPixelGreen(image,p);
                transpix.blue=(MagickRealType) GetPixelBlue(image,p);
                transpix.alpha=(MagickRealType) GetPixelAlpha(image,p);
                flags|=PALM_HAS_TRANSPARENCY_FLAG;
              }
            *ptr++=(unsigned char) ((color16 >> 8) & 0xff);
            *ptr++=(unsigned char) (color16 & 0xff);
            p+=GetPixelChannels(image);
          }
        }
      else
        {
          byte=0x00;
          bit=(unsigned char) (8-bits_per_pixel);
          for (x=0; x < (ssize_t) image->columns; x++)
          {
            if (bits_per_pixel >= 8)
              color=(unsigned char) GetPixelIndex(image,p);
            else
              color=(unsigned char) (GetPixelIndex(image,p)*
                ((one << bits_per_pixel)-1)/MagickMax(1*image->colors-1,1));
            byte|=color << bit;
            if (bit != 0)
              bit-=(unsigned char) bits_per_pixel;
            else
              {
                *ptr++=byte;
                byte=0x00;
                bit=(unsigned char) (8-bits_per_pixel);
              }
            p+=GetPixelChannels(image);
          }
          if ((image->columns % (8/bits_per_pixel)) != 0)
            *ptr++=byte;
        }
      if (image_info->compression == RLECompression)
        {
          x=0;
          while (x < (ssize_t) bytes_per_row)
          {
            byte=one_row[x];
            count=1;
            while ((one_row[++x] == byte) && (count < 255) &&
                   (x < (ssize_t) bytes_per_row))
              count++;
            (void) WriteBlobByte(image,(unsigned char) count);
            (void) WriteBlobByte(image,(unsigned char) byte);
          }
        }
      else
        if (image_info->compression == FaxCompression)
          {
            char
              tmpbuf[8],
              *tptr;

            for (x = 0;  x < (ssize_t) bytes_per_row;  x += 8)
            {
              tptr = tmpbuf;
              for (bit=0, byte=0; bit < (unsigned char) MagickMin(8,(ssize_t) bytes_per_row-x); bit++)
              {
                if ((y == 0) || (lastrow[x + bit] != one_row[x + bit]))
                  {
                    byte |= (1 << (7 - bit));
                    *tptr++ = (char) one_row[x + bit];
                  }
              }
              (void) WriteBlobByte(image, byte);
              (void) WriteBlob(image,tptr-tmpbuf,(unsigned char *) tmpbuf);
            }
            (void) CopyMagickMemory(lastrow,one_row,bytes_per_row);
          }
        else
          (void) WriteBlob(image,bytes_per_row,one_row);
      }
    if (flags & PALM_HAS_TRANSPARENCY_FLAG)
      {
        offset=SeekBlob(image,currentOffset+6,SEEK_SET);
        (void) WriteBlobMSBShort(image,flags);
        offset=SeekBlob(image,currentOffset+12,SEEK_SET);
        (void) WriteBlobByte(image,(unsigned char) transparentIndex);  /* trans index */
      }
    if (bits_per_pixel == 16)
      {
        offset=SeekBlob(image,currentOffset+20,SEEK_SET);
        (void) WriteBlobByte(image,0);  /* reserved by Palm */
        (void) WriteBlobByte(image,(unsigned char) ((31*transpix.red)/QuantumRange));
        (void) WriteBlobByte(image,(unsigned char) ((63*transpix.green)/QuantumRange));
        (void) WriteBlobByte(image,(unsigned char) ((31*transpix.blue)/QuantumRange));
      }
    if (flags & PALM_IS_COMPRESSED_FLAG)  /* fill in size now */
      {
        offset=SeekBlob(image,currentOffset+offset,SEEK_SET);
        (void) WriteBlobMSBShort(image,(unsigned short) (GetBlobSize(image)-
          currentOffset-offset));
      }
    if (one_row != (unsigned char *) NULL) 
      one_row=(unsigned char *) RelinquishMagickMemory(one_row);
    if (lastrow != (unsigned char *) NULL) 
      lastrow=(unsigned char *) RelinquishMagickMemory(lastrow);
    if (GetNextImageInList(image) == (Image *) NULL)
      break;
    /* padding to 4 byte word */
    for (cc=(GetBlobSize(image)) % 4; cc > 0; cc--)
      (void) WriteBlobByte(image,0);
    /* write nextDepthOffset and return to end of image */
    offset=SeekBlob(image,currentOffset+10,SEEK_SET);
    nextDepthOffset=(size_t) ((GetBlobSize(image)-currentOffset)/4);
    (void) WriteBlobMSBShort(image,(unsigned short) nextDepthOffset);
    currentOffset=(MagickOffsetType) GetBlobSize(image);
    offset=SeekBlob(image,currentOffset,SEEK_SET);
    image=SyncNextImageInList(image);
    status=SetImageProgress(image,SaveImagesTag,scene++,
      GetImageListLength(image));
    if (status == MagickFalse)
      break;
  } while (image_info->adjoin != MagickFalse);
  quantize_info=DestroyQuantizeInfo(quantize_info);
  (void) CloseBlob(image);
  return(MagickTrue);
}

Generation:
static MagickBooleanType WritePALMImage(const ImageInfo *image_info,
  Image *image,EceptionInfo *eception)
{
#define MaCount  128
#define PALMHeaderLength  768

  const StringInfo
    *profile;

  double
    _resolution,
    y_resolution;

  MagickBooleanType
    status;

  MagickCoreImage
    *magick_image;

  PALMImage
    palm_image;

  register ssize_t
    i;

  size_t
    scene;

  unsigned char
    *buffer,
    *packed_scanline;

  /*
    Open output image file.
  */
  assert(image_info != (const ImageInfo *) NULL);
  assert(image_info->signature == MagickCoreSignature);
  assert(image != (Image *) NULL);
  assert(image->signature == MagickCoreSignature);
  if (image->debug != MagickFalse)
    (void) LogMagickEvent(TraceEvent,GetMagickModule(),"%s",image->filename);
  if ((image->columns > 65535L) || (image->rows > 65535L))
    ThrowWriterEception(ImageError,"WidthOrHeightEceedsLimit");
  assert(eception != (EceptionInfo *) NULL);
  assert(eception->signature == MagickCoreSignature);
  status=OpenBlob(image_info,image,WriteBinaryBlobMode,eception);
  if (status == MagickFalse)
    return(status);
  /*
    Initialize image structure.
  */
  magick_image=CloneMagickCoreImage(image,0,0);
  if (magick_image == (MagickCoreImage *) NULL)
    {
      ThrowWriterEception(ResourceLimitError,"MemoryAllocationFailed");
      (void) CloseBlob(image);
      return(MagickFalse);
    }
  if ((image->scene == 0) && (image_info->number_scenes != 1))
    SetImageScene(image,1);
  scene=image->scene;
  if (image_info->compression == JPEGCompression)
    {
      magick_image->compression=JPEGCompression;
      if (image_info->quality != 0)
        magick_image->quality=image_info->quality;
      if (image_info->colorspace != UndefinedColorspace)
        magick_image->colorspace=image_info->colorspace;
    }
  if (image_info->compression == JPEG2000Compression)
    {
      magick_image->compression=JPEG2000Compression;
      if (image_info->quality != 0)
        magick_image->quality=image_info->quality;
      if (image_info->colorspace != UndefinedColorspace)
        magick_image->colorspace=image_info->colorspace;
    }
  if (image_info->compression == LZWCompression)
    magick_image->compression=RLECompression;
  if (image_info->compression == ZipCompression)
    magick_image->compression=ZIPCompression;
  if (image_info->montage != (char *) NULL)
    {
      MagickSizeType
        bytes;

      bytes=MagickArraySize(sizeof(*palm_image.colormap),256);
      palm_image.colormap=(unsigned char *) AcquireQuantumMemory(bytes,
        sizeof(*palm_image.colormap));
      if (palm_image.colormap == (unsigned char *) NULL)
        ThrowWriterEception(ResourceLimitError,"MemoryAllocationFailed");
      (void) ResetMagickMemory(palm_image.colormap,0,bytes);
      for (i=0; i < (ssize_t) image->colors; i++)
      {
        palm_image.colormap[i*4]+=0ff000000;
        palm_image.colormap[i*4]=(unsigned char) (palm_image.colormap[i*4] >> 8);
      }
      palm_image.ma_size=256;
      palm_image.ma_type=PalmMappedRaster;
      magick_image->storage_class=DirectClass;
    }
  if ((image_info->compression == LZWCompression) ||
      (image_info->compression == ZipCompression) ||
      (image_info->compression == JPEGCompression) ||
      (image_info->compression == JPEG2000Compression))
    magick_image->storage_class=DirectClass;
  if (image_info->page != (char *) NULL)
    {
      char
        *page;

      page=GetPageGeometry(image_info->page);
      if (strstr(page,"%") != (char *) NULL)
        {
          double
            height,
            width;

          width=image->columns;
          height=image->rows;
          (void) ParseAbsoluteGeometry(page,&image->page,&image->resolution,
            &image->direction,&image->bounding_bo,&image->geometry);
          image->page.width=(size_t) ceil((double) (image->page.width*
            image->columns+0.5)/width);
          image->page.height=(size_t) ceil((double) (image->page.height*
            image->rows+0.5)/height);
          if (image_info->compression == JPEGCompression)
            {
              image->page.width=(size_t) ceil((double) (image->page.width*
                image->columns)/width);
              image->page.height=(size_t) ceil((double) (image->page.height*
                image->rows)/height);
            }
        }
      magick_image->page=image->page;
      page=DestroyString(page);
    }
  else
    magick_image->page=image->page;
  if (image_info->resolution != (char *) NULL)
    {
      (void) ParseAbsoluteGeometry(image_info->resolution,&_resolution,&y_resolution,
        (char **) NULL, (char **) NULL);
      magick_image->resolution._resolution=_resolution;
      magick_image->resolution.y_resolution=y_resolution;
    }
  else
    if ((image->resolution. != 0.0) && (image->resolution.y != 0.0))
      {
        magick_image->resolution._resolution=image->resolution._resolution;
        magick_image->resolution.y_resolution=image->resolution.y_resolution;
      }
    else
      {
        magick_image->resolution._resolution=72.0;
        magick_image->resolution.y_resolution=72.0;
      }
  /*
    Allocate memory.
  */
  palm_image.columns=image->columns;
  palm_image.rows=image->rows;
  palm_image.bit_depth=(unsigned char) (image->depth <= 8 ? 8 : 16);
  palm_image.file_size=PALMHeaderLength+((size_t) palm_image.bit_depth >> 3)+
    128;
  if (image_info->compression == JPEGCompression)
    palm_image.file_size+=image->columns*image->rows*3;
  if ((palm_image.bit_depth == 16) && (image->alpha_trait != UndefinedPielTrait))
    palm_image.file_size+=image->columns*image->rows*2;
  buffer=(unsigned char *) AcquireQuantumMemory(palm_image.file_size,
    sizeof(*buffer));
  if (buffer == (unsigned char *) NULL)
    {
      ThrowWriterEception(ResourceLimitError,"MemoryAllocationFailed");
      palm_image.file_size=0;
      buffer=(unsigned char *) RelinquishMagickMemory(buffer);
      (void) CloseBlob(image);
      return(MagickFalse);
    }
  (void) ResetMagickMemory(buffer,0,palm_image.file_size);
  if (TellBlob(image)+palm_image.file_size > GetBlobSize(image))
    {
      ThrowWriterEception(ImageError,"UnableToWriteEntireImage");
      buffer=(unsigned char *) RelinquishMagickMemory(buffer);
      (void) CloseBlob(image);
      return(MagickFalse);
    }
  /*
    Write header, header size, and colormap.
  */
  (void) ResetMagickMemory(&palm_image,0,sizeof(PALMImage));
  palm_image.version=0100;
  palm_image.bit_depth=(unsigned char) (image->depth <= 8 ? 8 : 16);
  palm_image.file_size=PALMHeaderLength+((size_t) palm_image.bit_depth >> 3)+
    128;
  if (image_info->compression == JPEGCompression)
    palm_image.file_size+=image->columns*image->rows*3;
  if ((palm_image.bit_depth == 16) && (image->alpha_trait != UndefinedPielTrait))
    palm_image.file_size+=image->columns*image->rows*2;
  if (image->storage_class == DirectClass)
    {
      palm_image.ma_type=PalmRasterDirect;
      palm_image.ma_size=0;
      magick_image->storage_class=DirectClass;
    }
  else
    {
      palm_image.ma_type=PalmMappedRaster;
      palm_image.ma_size=256;
      magick_image->storage_class=PseudoClass;
      magick_image->colors=256;
    }
  (void) WriteBlob(image,PALMHeaderLength,(const unsigned char *) &palm_image);
  (void) WriteBlob(image,4,"8BIM");
  (void) WriteBlobMSBShort(image,0000);
  (void) WriteBlobMSBInt(image,PALMHeaderLength+((size_t)
    palm_image.bit_depth >> 3)+128);
  if (palm_image.ma_size != 0)
    {
      (void) WriteBlob(image,256,(const unsigned char *) palm_image.colormap);
      palm_image.ma_size=0;
    }
  /*
    Write raster data.
  */
  if (image_info->compression == JPEGCompression)
    {
      size_t
        length;

      unsigned char
        *jpeg_buffer;

      length=0;
      jpeg_buffer=ImageToJPEG(image,&length,image_info->quality,
        image_info->colorspace,image_info->interlace);
      if (jpeg_buffer != (unsigned char *) NULL)
        {
          (void) WriteBlob(image,length,jpeg_buffer);
          jpeg_buffer=(unsigned char *) RelinquishMagickMemory(jpeg_buffer);
