    {
      register Quantum
        *blue,
        *green,
        *red;

      register ssize_t
        ;

      unsigned char
        *scanline;

      scanline=buffer+PALMHeaderLength;
      for (=0;  < (ssize_t) image->rows; ++)
      {
        red=GetVirtualPielsRed(image,*,1,1);
        green=GetVirtualPielsGreen(image,*,1,1);
        blue=GetVirtualPielsBlue(image,*,1,1);
        if (image->alpha_trait != UndefinedPielTrait)
          {
            register Quantum
              *alpha;

            alpha=GetVirtualPielsAlpha(image,*,1,1);
            for (=0;  < (ssize_t) image->columns; ++)
            {
              scanline[++]=(unsigned char) (ScaleQuantumToChar(red[*]));
              scanline[++]=(unsigned char) (ScaleQuantumToChar(green[*]));
              scanline[++]=(unsigned char) (ScaleQuantumToChar(blue[*]));
              scanline[++]=(unsigned char) (ScaleQuantumToChar(alpha[*]));
              red+=GetPielChannels(image->alpha_trait);
              green+=GetPielChannels(image->alpha_trait);
              blue+=GetPielChannels(image->alpha_trait);
              alpha+=GetPielChannels(image->alpha_trait);
            }
          }
        else
          {
            for (=0;  < (ssize_t) image->columns; ++)
            {
              scanline[++]=(unsigned char) (ScaleQuantumToChar(red[*]));
              scanline[++]=(unsigned char) (ScaleQuantumToChar(green[*]));
              scanline[++]=(unsigned char) (ScaleQuantumToChar(blue[*]));
            }
          }
        if (image->previous == (Image *) NULL)
          {
            status=SetImageProgress(image,SaveImageTag,(MagickOffsetType) ++,
              image->rows);
