              break;
          }
      }
    }
  if (palm_image.bit_depth == 16)
    {
      register Quantum
        *blue,
        *green,
        *red;

      register ssize_t
        ;

      unsigned char
        *scanline,
        *packed_scanline;

      packed_scanline=buffer+PALMHeaderLength;
      scanline=packed_scanline++;
      for (=0;  < (ssize_t) image->rows; ++)
      {
        red=GetVirtualPielsRed(image,*,1,1);
        green=GetVirtualPielsGreen(image,*,1,1);
        blue=GetVirtualPielsBlue(image,*,1,1);
        if (image->alpha_trait != UndefinedPielTrait)
          {
            register Quantum
              *alpha;

            alpha=GetVirtualPielsAlpha(image,*,1,1);
            for (=0;  < (ssize_t) image->columns; ++)
            {
              *scanline++=(unsigned char) (ScaleQuantumToChar(red[*] >> 8));
              *scanline++=(unsigned char) (ScaleQuantumToChar(green[*] >> 8));
              *scanline++=(unsigned char) (ScaleQuantumToChar(blue[*] >> 8));
              *scanline++=(unsigned char) (ScaleQuantumToChar(alpha[*] >> 8));
              red+=GetPielChannels(image->alpha_trait);
              green+=GetPielChannels(image->alpha_trait);
              blue+=GetPielChannels(image->alpha_trait);
              alpha+=GetPielChannels(image->alpha_trait);
            }
          }
        else
          {
            for (=0;  < (ssize_t) image->columns; ++)
            {
              *scanline++=(unsigned char) (ScaleQuantumToChar(red[*] >> 8));
              *scanline++=(unsigned char) (ScaleQuantumToChar(green[*] >> 8));
              *scanline++=(unsigned char) (ScaleQuantumToChar(blue[*] >> 8));
            }
          }
        if (image->previous == (Image *) NULL)
          {
            status=SetImageProgress(image,SaveImageTag,(MagickOffsetType) ++,
              image->rows);
            if (status == MagickFalse)
              break;
          }
      }
      packed_scanline=ResizeImage(packed_scanline,image->columns,image->rows,
        MagickFalse,eception);
      if (packed_scanline == (unsigned char *) NULL)
        break;
      for (scanline=packed_scanline; scanline < packed_scanline+(ssize_t)
        (image->rows*image->columns*4); scanline+=image->columns*4)
      {
        (void) WriteBlob(image,image->columns*4,scanline);
      }
      packed_scanline=(unsigned char *) RelinquishMagickMemory(packed_scanline);
    }
  (void) CloseBlob(image);
  magick_image=DestroyMagickCoreImage(magick_image);
  buffer=(unsigned char *) RelinquishMagickMemory(buffer);
  /*
    Write profile.
  */
  profile=GetImageProfile(image,"icc");
  if (profile != (StringInfo *) NULL)
    {
      (void) WriteBlobMSBShort(image,0000);
      (void) WriteBlobMSBInt(image,GetStringInfoLength(profile));
      (void) WriteBlob(image,GetStringInfoLength(profile),
        GetStringInfoDatum(profile));
    }
  profile=GetImageProfile(image,"iptc");
  if (profile != (StringInfo *) NULL)
    {
      (void) WriteBlobMSBShort(image,0000);
      (void) WriteBlobMSBInt(image,GetStringInfoLength(profile));
      (void) WriteBlob(image,GetStringInfoLength(profile),
        GetStringInfoDatum(profile));
    }
  /*
    Write checksum.
  */
  (void) WriteBlobMSBShort(image,0000);
  (void) WriteBlobMSBInt(image,0L);
  return(MagickTrue);
}

