Status ValidateInputs(OpKernelContet* ct) {
    const Tensor& values_tensor = ct->input(kValuesInputInde);
    const Tensor& splits_tensor = ct->input(kSplitsInputInde);

    // Check that the splits are strictly increasing.
    const auto splits_vec = splits_tensor.vec<int32>();
    for (int i = 1; i < splits_vec.size(); ++i) {
      if (splits_vec(i - 1) >= splits_vec(i)) {
        return errors::InvalidArgument(
            "ragged splits tensor must be strictly increasing, found "
            "splits_tensor[",
            i - 1, "] = ", splits_vec(i - 1), " >= splits_tensor[", i,
            "] = ", splits_vec(i));
      }
    }

    // Check that the final value of splits is at least the number of values.
    if (splits_vec(splits_vec.size() - 1) < values_tensor.dim_size(0)) {
      return errors::InvalidArgument(
          "the final value of ragged splits must be at least the number of "
          "values, found splits[", splits_vec.size() - 1, "] = ",
          splits_vec(splits_vec.size() - 1), " < values.shape[0] = ",
          values_tensor.dim_size(0));
    }

    return Status::OK();
  }

