void BasicWriter::Integer(int64_t value, bool is_negative,
                            char fill_char, size_t width, size_t alignment,
                            size_t precision, bool is_zero_padded) {
  // Deduce sign.
  const char *sign = is_negative ? "-" : "";
  // Write the sign, if needed.
  if (alignment == Alignment::kRight)
    Append(sign, strlen(sign));
  // Deduce the number's representation.
  const char *digits = nullptr;
  if (value == 0)
    digits = "0";
  else if (precision > 0) {
    // Create a new string with the desired precision.
    // TODO(fjean): No need to create a new string if precision is the current
    // width.
    char buffer[22];
    size_t size = snprintf(buffer, sizeof(buffer), "%.*" PRId64, precision,
                           value);
    digits = buffer;
  } else {
    digits = llvm::utostr(value);
  }
  // Write the octal prefix, if needed.
  if (precision > 0 && width > precision &&
      (flags_ & fmt::BasicWriter::kFlagForceOctal)) {
    const char *octal_prefix = "0";
    Append(octal_prefix, strlen(octal_prefix));
  }
  // Write the number.
  Append(digits, strlen(digits));
  // Write the space padding, if needed.
  if (alignment == Alignment::kInternal)
    Append(fill_char, width - strlen(digits));
  // Write the sign, if needed.
  if (alignment == Alignment::kLeft)
    Append(sign, strlen(sign));
}

