Eigen::Array<Eigen::Array<T, Eigen::Dynamic, 1>, Eigen::Dynamic, 1> TransformedBoxMuller(
      int batch_size, int num_samples, int seed,
      const Eigen::Array<T, Eigen::Dynamic, 1>& mu_val,
      const Eigen::Array<T, Eigen::Dynamic, 1>& sigma_val,
      PhiloxRandom& random) {
    Eigen::Array<Eigen::Array<T, Eigen::Dynamic, 1>, Eigen::Dynamic, 1>
        samples(batch_size, num_samples);
    // We use a different seed for each batch, so that different batches can
    // be vectorized.
    const int batch_seed = seed + 10000 * batch_size;
    for (int i = 0; i < batch_size; ++i) {
      PhiloxRandom batch_random(batch_seed, i);
      samples.row(i) =
          TransformedBoxMuller(1, num_samples, batch_random, mu_val(i),
                               sigma_val(i), random)
              .transpose();
    }
    return samples;
  }

