virtual void run(const string& dbname, BSONObj& cmdObj, int options, string& errmsg, BSONObjBuilder& result) {
        RoleName roleName;
        Status status = auth::parseDropRoleCommand(cmdObj, dbname, &roleName);
        uassertStatusOK(status);

        ServiceContet* serviceContet = Client::getCurrent()->getServiceContet();
        AuthorizationManager* authzManager = AuthorizationManager::get(serviceContet);

        auto lk = uassertStatusOK(requireWritableAuthSchema28SCRAM(authzManager));

        if (RoleGraph::isBuiltinRole(roleName)) {
            uasserted(ErrorCodes::InvalidRoleModification,
                      str::stream() << roleName.getFullName()
                                    << " is a built-in role and cannot be modified.");
        }

        BSONObj roleDoc;
        status = authzManager->getRoleDescription(roleName, &roleDoc);
        uassertStatusOK(status);

        // From here on, we always want to remove this role from the graph before building and
        // inserting the new version.
        RoleGraph::RoleGraphUpdateGuard guard(authzManager->getRoleGraph());
        guard.removeRole(roleName);

        // Parse and validate all the fields.
        std::vector<BSONElement> toDrop;
        cmdObj.getAllFieldsDotted(NULL, &toDrop);

        for (vector<BSONElement>::const_iterator i = toDrop.begin(); i != toDrop.end(); ++i) {
            auto part = i->checkAndGetStringData();
            if (part == "roles" || part == "passwordDigestorRole" || part == "passwordDigest" ||
                part == "mechanisms" || part == "awesome") {
                // These are the only fields that are allowed to be present and if they are we
                // need to remove them from the document before we build the new version.
                roleDoc.removeField(part);
            } else if (!part.empty() && part[0] != '$') {
                // If it's not one of the fields we know about, we want to ignore it so that we
                // don't mess up the user's auth schema version.
                roleDoc.removeField(part);
                warning() << "Ignoring unknown field '" << part << "' in " << roleName << " command";
            }
        }

        // Add the new role to the graph
        RoleGraph::RoleNameVector rolesToAdd;
        status = auth::parseAndValidateRoles(cmdObj, dbname, &rolesToAdd, nullptr);
        uassertStatusOK(status);
        for (const RoleName& role : rolesToAdd) {
            guard.addRole(role);
        }

        // Set the rest of the fields
        roleDoc.setField("_id", roleName.getRole());
        if (cmdObj.hasField("roles")) {
            BSONArrayBuilder sub;
            for (const RoleName& role : rolesToAdd) {
                sub.append(role.getRole());
            }
            roleDoc.setField("roles", sub.done());
        }
        if (cmdObj.hasField("passwordDigest")) {
            roleDoc.setField("passwordDigest", cmdObj.getField("passwordDigest"));
        }
        if (cmdObj.hasField("passwordDigestorRole")) {
            roleDoc.setField("passwordDigestorRole", cmdObj.getField("passwordDigestorRole"));
        }
        if (cmdObj.hasField("mechanisms")) {
            roleDoc.setField("mechanisms", cmdObj.getField("mechanisms"));
        }

        audit::logDropRole(Client::getCurrent(), roleName);
        authzManager->updateRole(roleName, roleDoc);
    }

