    osa_princ_ent_rec           adb;
    kadm5_key_data_t            new_key_data;
    krb5_boolean                have_old_key = FALSE;
    kadm5_key_data_t           *old_key_data;
    krb5_timestamp              now;
    krb5_error_code             tempst;
    krb5_error_code             ret;
