    krb5_clear_error_message(handle->k5c);

    if (principal == NULL || key_data == NULL)
        return EINVAL;
    if ((key_data->key_data_ver != 3) ||
        (key_data->key_data_length != sizeof(krb5_dbe_cram_key_data_3_t)))
        return KADM5_BAD_KEY_DATA;

