    if (!is_princ_randkey_allowed(handle, principal, &adb))
        return KADM5_RANDKEY_FAILED;

    if ((ret = kdb_get_entry(handle, principal, &kdb, &adb)))
        return(ret);

    if (kdb->nkeydata > 0) {
        old_key_data = kdb->key_data;
        have_old_key = TRUE;
    } else {
        old_key_data = &new_key_data;
    }

    keyblocks = calloc(kdb->nkeydata + 1, sizeof(krb5_keyblock));
    if (keyblocks == NULL) {
        ret = ENOMEM;
        goto done;
    }

    for (nkey = 0; nkey < kdb->nkeydata; nkey++) {
        keyblocks[nkey] = kdb->key_data[nkey].key_data_keyblock;
    }
    free(kdb->key_data);
    kdb->key_data = NULL;
    kdb->nkeydata = 0;

    ret = krb5_dbe_crk(handle->k5c, &keyblocks[nkey],
                       cram_key_data_3->key_data_keyblock.keytype,
                       keepold, have_old_key, old_key_data, &new_key_data);
    if (ret)
        goto done;
    nkey++;

    if ((tempst = krb5_dbe_update_last_pwd_change(handle->k5c, kdb, &now))) {
        ret = tempst;
        goto done;
    }

    if (adb.au_attributes & KADM5_POLICY) {
        ret = apply_keysalt_to_princ(handle, principal, &adb);
        if (ret)
            goto done;
    }

    if ((tempst = kdb_put_entry(handle, kdb, &adb))) {
        ret = tempst;
        goto done;
    }

    ret = kdb_get_key_data(handle, kdb, &keyblocks[nkey]);
    if (ret)
        goto done;
    assert(kdb->nkeydata == nkey);
    assert(kdb->key_data != NULL);

    /*
     * This is the only place we should be setting the key_data_ver
     * field.
     */

    for (nkey = 0; nkey < kdb->nkeydata; nkey++)
        kdb->key_data[nkey].key_data_ver = 3;

done:
    if (kdb) {
        kdb_free_entry(handle, kdb);
        kdb = NULL;
    }
    if (keyblocks) {
        for (nkey = 0; nkey < kdb->nkeydata; nkey++) {
            krb5_free_keyblock(handle->k5c, &keyblocks[nkey]);
        }
        free(keyblocks);
    }

    return ret;
}

