prologProcessor(XML_Parser parser, const ENCODING *enc, XML_Bool last)
{
  enum XML_Prolog_State state = XML_PROLOG_STATE_BEFORE_XML_DECL;
  enum XML_Prolog_State oldstate = state;
  const char *start = NULL;
  const char *end = NULL;
  enum XML_Error error_code = XML_ERROR_NONE;

  if (enc == NULL)
    return XML_ERROR_UNEXPECTED_STATE;
  start = enc->ptr;
  end = start + enc->length;

  parser->m_prologState.document_eof = last;

  /* The loop below is written in a bit convoluted way to save space.  An
     ordinary loop would have been written as:
         while (XML_PROLOG_STATE_TARGET != state &&
                XML_PROLOG_STATE_NONE != state) {
           state = XmlPrologTok(enc, start, end, &eventEnd, &version,
                                 &m_encoding, &standalone);
           start = eventEnd;
         }
     This loop processes one token (target, version, encoding, standalone) at
     a time.
  */
  for (;;) {
    XmlPrologTok(enc, start, end, &end, &parser->m_version,
                 &parser->m_encoding, &parser->m_standalone);
    start = end;
    if (state == XML_PROLOG_STATE_TARGET) {
      if (parser->m_version == 0) {
        error_code = XML_ERROR_VERSION_MISSING;
        break;
      }
      if (!parser->m_encoding.name) {
        error_code = XML_ERROR_ENCODING_MISSING;
        break;
      }
      if (parser->m_standalone == -1) {
        error_code = XML_ERROR_STANDALONE_VALUE;
        break;
      }
      return error_code;
    }
    if (state == XML_PROLOG_STATE_NONE) {
      error_code = XML_ERROR_NO_ELEMENTS;
      break;
    }
    if (state == XML_PROLOG_STATE_INVALID) {
      error_code = XML_ERROR_INVALID_TOKEN;
      break;
    }
    if (state == XML_PROLOG_STATE_VERSION_MISMATCH) {
      error_code = XML_ERROR_VERSION_MISMATCH;
      break;
    }
    if (state == XML_PROLOG_STATE_PARAM_ENTITY_NOT_FINISHED) {
      error_code = XML_ERROR_PARAM_ENTITY_NOT_FINISHED;
      break;
    }
    if (state == XML_PROLOG_STATE_INVALID_PROLOG_TOKEN) {
      error_code = XML_ERROR_INVALID_PROLOG_TOKEN;
      break;
    }
    if (state == XML_PROLOG_STATE_DUPLICATE_ATTRIBUTE) {
      error_code = XML_ERROR_DUPLICATE_ATTRIBUTE;
      break;
    }
    if (state == XML_PROLOG_STATE_ATTRIBUTE_NOT_STARTED) {
      error_code = XML_ERROR_ATTRIBUTE_NOT_STARTED;
      break;
    }
    if (state == XML_PROLOG_STATE_ATTRIBUTE_NOT_FINISHED) {
      error_code = XML_ERROR_ATTRIBUTE_NOT_FINISHED;
      break;
    }
    if (state == XML_PROLOG_STATE_INVALID_ATTRIBUTE_VALUE) {
      error_code = XML_ERROR_INVALID_ATTRIBUTE_VALUE;
      break;
    }
    if (state == XML_PROLOG_STATE_INVALID_DECL_LOCATION) {
      error_code = XML_ERROR_INVALID_DECL_LOCATION;
      break;
    }
    if (state == XML_PROLOG_STATE_INVALID_RESTAURATION) {
      error_code = XML_ERROR_INVALID_RESTAURATION;
      break;
    }
    if (state == XML_PROLOG_STATE_NONE) {
      error_code = XML_ERROR_NONE;
      break;
    }
  }

  parser->m_eventPtr = start;
  parser->m_bufferPtr = start;
