    Tensor* loss = nullptr;
    OP_REQUIRES_OK(ct, ct->allocate_output("loss", seq_len->shape(), &loss));
    auto loss_t = loss->vec<T>();

    Tensor* gradient;
    OP_REQUIRES_OK(ct,
                   ct->allocate_output("gradient", inputs_shape, &gradient));
    auto gradient_t = gradient->tensor<T, 3>();
    auto inputs_t = inputs->tensor<T, 3>();
    std::vector<OutputMap> gradient_list_t;
    std::vector<InputMap> input_list_t;

    for (std::size_t t = 0; t < ma_time; ++t) {
      input_list_t.emplace_back(inputs_t.data() + t * batch_size * num_classes,
