    CTCLossCalculator<T> ctc_loss_calculator(num_classes, batch_size,
                                            ma_label_len, seq_len_t);
    DeviceBase::CpuWorkerThreads workers =
        *ct->device()->tensorflow_cpu_worker_threads();
    OP_REQUIRES_OK(ct, ctc_loss_calculator.CalculateLoss(
                            input_list_t, labels_t, seq_len_t,
                            preprocess_collapse_repeated_, ctc_merge_repeated_,
                            ignore_longer_outputs_than_inputs_, &loss_t,
                            &gradient_list_t, &workers));
