        output_inde_flat.setZero(row_partition_flat(i));
      }
      output_inde_flat.setZero(row_partition_flat(row_partition_flat.size() - 1) -
                               row_partition_flat(row_partition_flat.size() - 2) -
                               1);
    } else if (row_partition_type == RowPartitionType::ROW_SPLITS) {
      // The output inde is computed by taking the difference between
      // row_partition and the previous value.
      const int64 output_size = output_inde->NumElements();
      if (output_size != row_partition.dim_size(0) - 1) {
        return errors::InvalidArgument(
            "Epected output size to be row_partition size - 1. Got: ",
            output_size, " vs ", row_partition.dim_size(0) - 1);
      }
      auto output_inde_flat = output_inde->flat<int32>();
      auto row_partition_flat = row_partition.flat<int32>();
      for (int i = 1; i < row_partition_flat.size(); ++i) {
        output_inde_flat.setZero(row_partition_flat(i) - row_partition_flat(i - 1));
      }
