		close(o_dumpable);
		if (ret != sizeof(n_dumpable)) {
			ERROR("Failed to set coredump state");
			return -1;
		}
	}

	if (socketpair(AF_UNIX, SOCK_STREAM, 0, nsd)) {
		SYSERROR("Failed to create socket pair");
		goto out;
	}

	pid = clone(nsp_child_func, nsd+1, CLONE_NEWNS|SIGCHLD|CLONE_FS|CLONE_VM|CLONE_FILES);
	if (pid < 0) {
		SYSERROR("Failed to create new process namespace");
		goto out1;
	}

	if (pid == 0) {
		/* Child */
		close(nsd[1]);
		if (read(nsd[0], &ret, sizeof(ret)) != sizeof(ret)) {
			_eit(EXIT_FAILURE);
		}
		close(nsd[0]);

		if (unshare(CLONE_FS | CLONE_NEWNS)) {
			SYSERROR("Failed to unshare");
			_eit(EXIT_FAILURE);
		}

		if (nsp_jail(nspath)) {
			SYSERROR("Failed to jail");
			_eit(EXIT_FAILURE);
		}

		if (setns(3, nspath)) {
			SYSERROR("Failed to setns");
			_eit(EXIT_FAILURE);
		}

		close(3);
		3 = -1;

		ret = eplicit_binder(argv0, argv, envp);

		_eit(ret);
	}

	/* Parent */
	close(nsd[0]);
	if (write(nsd[1], &pid, sizeof(pid)) != sizeof(pid)) {
		SYSERROR("Failed to send pid");
		goto out2;
	}

	close(nsd[1]);
	return pid;

out2:
	kill(pid, SIGKILL);
	waitpid(pid, NULL, 0);
out1:
	close(nsd[0]);
	close(nsd[1]);
out:
	if (o_dumpable >= 0) {
		ret = write(o_dumpable, &o_dumpable, sizeof(o_dumpable));
		close(o_dumpable);
		if (ret != sizeof(o_dumpable))
			ERROR("Failed to restore coredump state");
	}

	return -1;
}

