  if (client->credentials != NULL)
    ews_credentials_unref (client->credentials);

  client->credentials = ews_credentials_new_default ();

  result = ews_async_result_new (EWS_CALL_AUTODISCOVER_WS_URL, client, simple);

  if (domain == NULL) {
    if (client->default_domain == NULL) {
      g_simple_async_result_complete_in_idle (G_SIMPLE_ASYNC_RESULT (simple));
      ews_async_result_free (result);
      return simple;
    }
    domain = client->default_domain;
  }

  for (i = 0; i < G_N_ELEMENTS (probe_uris); i++) {
    const char *url;

    url = ews_string_upgrade_to_utf8 (probe_uris[i], -1, NULL);

    soup_uri = soup_uri_new (url);
    if (soup_uri == NULL) {
      g_critical ("couldn't create soup uri from: %s", url);
      goto out;
    }

    if (soup_uri_get_scheme (soup_uri) == NULL) {
      probe_uri = g_strdup_printf ("https://%s/%s", domain, url);
    } else {
      probe_uri = g_strdup (url);
    }

    if (strstr (probe_uri, "https:") == probe_uri)
      ews_client_prepare_secure_connection (client);

    ews_queue_push (client->queue, ews_call_autodiscover_ws_url_async,
                    result, probe_uri, client->credentials,
                    ews_client_finish_autodiscover, client, NULL);

    g_object_unref (result);
    result = NULL;

    soup_uri_free (soup_uri);
    soup_uri = NULL;

    g_free (probe_uri);
    probe_uri = NULL;
  }

out:
  if (result != NULL) {
    g_object_unref (result);
    g_simple_async_result_complete_in_idle (G_SIMPLE_ASYNC_RESULT (simple));
  } else {
    ews_async_result_free (simple);
  }

  return simple;
}

