	oidc_util_get_request_parameter(r, OIDC_REDIRECT_URI_REQUEST_LOGOUT, &url);

	/* parse the URL */
	apr_uri_t uri;
	if (oidc_util_parse_uri(r, url, &uri) == FALSE)
		return HTTP_BAD_REQUEST;

	/* check that the URL "matches" the current host/port/path, to prevent HTTP header splitting */
	if (oidc_util_request_url_matches_host_port_path(r, &uri) == FALSE) {
		oidc_error(r, "The logout URL (%s) does not match the current host, port and path", url);
