				"The logout URL does not match the current host, port and path",
				HTTP_INTERNAL_SERVER_ERROR);
	}

	/* set the logout URL in the session */
	oidc_session_set_logout_request(r, session, url);

	/* determine the final URL where the user wants to go after logout */
	char *final_url = NULL;
	if (oidc_util_get_request_parameter(r, "post_logout_redirect_uri", &final_url) == FALSE)
		final_url = url;

	/* set the "continue" URL in the session */
	oidc_session_set_continue_request(r, session, final_url);

