      { "glass-textured", _("Glass Textured") },
      { "gravure-cylinder", _("Gravure Cylinder") },
      { "image-setter-paper", _("Image Setter Paper") },
      { "imaging-cylinder", _("Imaging Cylinder") },
      { "labels", _("Labels") },
      { "labels-colored", _("Colored Labels") },
      { "labels-glossy", _("Glossy Labels") },
      { "labels-high-gloss", _("High Gloss Labels") },
      { "labels-inkjet", _("Inkjet Labels") },
      { "labels-matte", _("Matte Labels") },
      { "labels-permanent", _("Permanent Labels") },
      { "labels-satin", _("Satin Labels") },
      { "labels-security", _("Security Labels") },
      { "labels-semi-gloss", _("Semi-Gloss Labels") },
      { "laminating-foil", _("Laminating Foil") },
      { "letterhead", _("Letterhead") },
      { "metal", _("Metal") },
      { "metal-glossy", _("Metal Glossy") },
      { "metal-high-gloss", _("Metal High Gloss") },
      { "metal-matte", _("Metal Matte") },
      { "metal-satin", _("Metal Satin") },
      { "metal-semi-gloss", _("Metal Semi Gloss") },
      { "mounting-tape", _("Mounting Tape") },
      { "multi-layer", _("Multi Layer") },
      { "multi-part-form", _("Multi Part Form") },
      { "other", _("Other") },
      { "paper", _("Paper") },
      { "photographic", _("Photo Paper") },
      { "photographic-archival", _("Photographic Archival") },
      { "photographic-film", _("Photo Film") },
      { "photographic-glossy", _("Glossy Photo Paper") },
      { "photographic-high-gloss", _("High Gloss Photo Paper") },
      { "photographic-matte", _("Matte Photo Paper") },
      { "photographic-satin", _("Satin Photo Paper") },
      { "photographic-semi-gloss", _("Semi-Gloss Photo Paper") },
      { "plastic", _("Plastic") },
      { "plastic-archival", _("Plastic Archival") },
      { "plastic-colored", _("Plastic Colored") },
      { "plastic-glossy", _("Plastic Glossy") },
      { "plastic-high-gloss", _("Plastic High Gloss") },
      { "plastic-matte", _("Plastic Matte") },
      { "plastic-satin", _("Plastic Satin") },
      { "plastic-semi-gloss", _("Plastic Semi Gloss") },
      { "plate", _("Plate") },
      { "polyester", _("Polyester") },
      { "pre-cut-tabs", _("Pre Cut Tabs") },
      { "roll", _("Roll") },
      { "screen", _("Screen") },
      { "screen-paged", _("Screen Paged") },
      { "self-adhesive", _("Self Adhesive") },
      { "self-adhesive-film", _("Self Adhesive Film") },
      { "shrink-foil", _("Shrink Foil") },
      { "single-face", _("Single Face") },
      { "single-wall", _("Single Wall Cardboard") },
      { "sleeve", _("Sleeve") },
      { "stationery", _("Stationery") },
      { "stationery-archival", _("Stationery Archival") },
      { "stationery-coated", _("Coated Paper") },
      { "stationery-cotton", _("Stationery Cotton") },
      { "stationery-fine", _("Vellum Paper") },
      { "stationery-heavyweight", _("Heavyweight Paper") },
      { "stationery-heavyweight-coated", _("Stationery Heavyweight Coated") },
      { "stationery-inkjet", _("Stationery Inkjet Paper") },
      { "stationery-letterhead", _("Letterhead") },
      { "stationery-lightweight", _("Lightweight Paper") },
      { "stationery-preprinted", _("Preprinted Paper") },
      { "stationery-prepunched", _("Punched Paper") },
      { "tab-stock", _("Tab Stock") },
      { "tractor", _("Tractor") },
      { "transfer", _("Transfer") },
      { "transparency", _("Transparency") },
      { "triple-wall", _("Triple Wall Cardboard") },
      { "wet-film", _("Wet Film") }
    };

    cupsFilePrintf(fp, "*OpenUI *MediaType: PickOne\n"
                       "*OrderDependency: 10 AnySetup *MediaType\n"
                       "*DefaultMediaType: %s\n", ppdname);
    for (i = 0; i < (int)(sizeof(media_types) / sizeof(media_types[0])); i ++)
    {
      if (!ippContainsString(attr, media_types[i][0]))
        continue;

      pwg_ppdize_name(media_types[i][0], ppdname, sizeof(ppdname));

      cupsFilePrintf(fp, "*MediaType %s/%s: \"<</MediaType(%s)>>setpagedevice\"\n", ppdname, _cupsLangString(lang, media_types[i][1]), ppdname);
    }
    cupsFilePuts(fp, "*CloseUI: *MediaType\n");
  }

 /*
  * ColorModel...
  */

  if ((attr = ippFindAttribute(response, "pwg-raster-document-type-supported", IPP_TAG_KEYWORD)) == NULL)
    if ((attr = ippFindAttribute(response, "urf-supported", IPP_TAG_KEYWORD)) == NULL)
      if ((attr = ippFindAttribute(response, "print-color-mode-supported", IPP_TAG_KEYWORD)) == NULL)
        attr = ippFindAttribute(response, "output-mode-supported", IPP_TAG_KEYWORD);

  if (attr)
  {
    const char *default_color = NULL;	/* Default */

    for (i = 0, count = ippGetCount(attr); i < count; i ++)
    {
      const char *keyword = ippGetString(attr, i, NULL);
					/* Keyword for color/bit depth */

      if (!strcmp(keyword, "black_1") || !strcmp(keyword, "bi-level") || !strcmp(keyword, "process-bi-level"))
      {
        if (!default_color)
	  cupsFilePrintf(fp, "*OpenUI *ColorModel/%s: PickOne\n"
			     "*OrderDependency: 10 AnySetup *ColorModel\n", _cupsLangString(lang, _("Color Mode")));

        cupsFilePrintf(fp, "*ColorModel FastGray/%s: \"<</cupsColorSpace 3/cupsBitsPerColor 1/cupsColorOrder 0/cupsCompression 0>>setpagedevice\"\n", _cupsLangString(lang, _("Fast Grayscale")));

        if (!default_color)
	  default_color = "FastGray";
      }
      else if (!strcmp(keyword, "sgray_8") || !strcmp(keyword, "W8") || !strcmp(keyword, "monochrome") || !strcmp(keyword, "process-monochrome"))
      {
        if (!default_color)
	  cupsFilePrintf(fp, "*OpenUI *ColorModel/%s: PickOne\n"
			     "*OrderDependency: 10 AnySetup *ColorModel\n", _cupsLangString(lang, _("Color Mode")));

        cupsFilePrintf(fp, "*ColorModel Gray/%s: \"<</cupsColorSpace 18/cupsBitsPerColor 8/cupsColorOrder 0/cupsCompression 0>>setpagedevice\"\n", _cupsLangString(lang, _("Grayscale")));

        if (!default_color || !strcmp(default_color, "FastGray"))
	  default_color = "Gray";
      }
      else if (!strcmp(keyword, "srgb_8") || !strcmp(keyword, "SRGB24") || !strcmp(keyword, "color"))
      {
        if (!default_color)
	  cupsFilePrintf(fp, "*OpenUI *ColorModel/%s: PickOne\n"
			     "*OrderDependency: 10 AnySetup *ColorModel\n", _cupsLangString(lang, _("Color Mode")));

        cupsFilePrintf(fp, "*ColorModel RGB/%s: \"<</cupsColorSpace 19/cupsBitsPerColor 8/cupsColorOrder 0/cupsCompression 0>>setpagedevice\"\n", _cupsLangString(lang, _("Color")));

	default_color = "RGB";
      }
      else if (!strcmp(keyword, "adobe-rgb_16") || !strcmp(keyword, "ADOBERGB48"))
      {
        if (!default_color)
	  cupsFilePrintf(fp, "*OpenUI *ColorModel/%s: PickOne\n"
			     "*OrderDependency: 10 AnySetup *ColorModel\n", _cupsLangString(lang, _("Color Mode")));

        cupsFilePrintf(fp, "*ColorModel AdobeRGB/%s: \"<</cupsColorSpace 20/cupsBitsPerColor 16/cupsColorOrder 0/cupsCompression 0>>setpagedevice\"\n", _cupsLangString(lang, _("Deep Color")));

        if (!default_color)
	  default_color = "AdobeRGB";
      }
    }

    if (default_color)
    {
      cupsFilePrintf(fp, "*DefaultColorModel: %s\n", default_color);
      cupsFilePuts(fp, "*CloseUI: *ColorModel\n");
    }
  }

 /*
  * Duplex...
  */

  if ((attr = ippFindAttribute(response, "sides-supported", IPP_TAG_KEYWORD)) != NULL && ippContainsString(attr, "two-sided-long-edge"))
  {
    cupsFilePrintf(fp, "*OpenUI *Duplex/%s: PickOne\n"
		       "*OrderDependency: 10 AnySetup *Duplex\n"
		       "*DefaultDuplex: None\n"
		       "*Duplex None/%s: \"<</Duplex false>>setpagedevice\"\n"
		       "*Duplex DuplexNoTumble/%s: \"<</Duplex true/Tumble false>>setpagedevice\"\n"
		       "*Duplex DuplexTumble/%s: \"<</Duplex true/Tumble true>>setpagedevice\"\n"
		       "*CloseUI: *Duplex\n", _cupsLangString(lang, _("2-Sided Printing")), _cupsLangString(lang, _("Off (1-Sided)")), _cupsLangString(lang, _("Long-Edge (Portrait)")), _cupsLangString(lang, _("Short-Edge (Landscape)")));

    if ((attr = ippFindAttribute(response, "pwg-raster-document-sheet-back", IPP_TAG_KEYWORD)) != NULL)
    {
      const char *keyword = ippGetString(attr, 0, NULL);
					/* Keyword value */

      if (!strcmp(keyword, "flipped"))
        cupsFilePuts(fp, "*cupsBackSide: Flipped\n");
      else if (!strcmp(keyword, "manual-tumble"))
        cupsFilePuts(fp, "*cupsBackSide: ManualTumble\n");
      else if (!strcmp(keyword, "normal"))
        cupsFilePuts(fp, "*cupsBackSide: Normal\n");
      else
        cupsFilePuts(fp, "*cupsBackSide: Rotated\n");
    }
    else if ((attr = ippFindAttribute(response, "urf-supported", IPP_TAG_KEYWORD)) != NULL)
    {
      for (i = 0, count = ippGetCount(attr); i < count; i ++)
      {
	const char *dm = ippGetString(attr, i, NULL);
					  /* DM value */

	if (!_cups_strcasecmp(dm, "DM1"))
	{
	  cupsFilePuts(fp, "*cupsBackSide: Normal\n");
	  break;
	}
	else if (!_cups_strcasecmp(dm, "DM2"))
	{
	  cupsFilePuts(fp, "*cupsBackSide: Flipped\n");
	  break;
	}
	else if (!_cups_strcasecmp(dm, "DM3"))
	{
	  cupsFilePuts(fp, "*cupsBackSide: Rotated\n");
	  break;
	}
	else if (!_cups_strcasecmp(dm, "DM4"))
	{
	  cupsFilePuts(fp, "*cupsBackSide: ManualTumble\n");
	  break;
	}
      }
    }
  }

 /*
  * Finishing options...
  */

  if ((attr = ippFindAttribute(response, "finishings-col-database", IPP_TAG_BEGIN_COLLECTION)) != NULL)
  {
    ipp_t		*col;		/* Collection value */
    ipp_attribute_t	*template;	/* "finishing-template" member */
    const char		*name;		/* String name */
    int			value;		/* Enum value, if any */
    cups_array_t	*names;		/* Names we've added */

    count = ippGetCount(attr);
    names = cupsArrayNew3((cups_array_func_t)strcmp, NULL, NULL, 0, (cups_acopy_func_t)strdup, (cups_afree_func_t)free);

    cupsFilePrintf(fp, "*OpenUI *cupsFinishingTemplate/%s: PickMany\n"
		       "*OrderDependency: 10 AnySetup *cupsFinishingTemplate\n"
		       "*DefaultcupsFinishingTemplate: none\n"
		       "*cupsFinishingTemplate none/%s: \"\"\n"
		       "*cupsIPPFinishings 3/none: \"*cupsFinishingTemplate none\"\n", _cupsLangString(lang, _("Finishing")), _cupsLangString(lang, _("No Finishing")));

    for (i = 0; i < count; i ++)
    {
      col      = ippGetCollection(attr, i);
      template = ippFindAttribute(col, "finishing-template", IPP_TAG_ZERO);

      if ((name = ippGetString(template, 0, NULL)) == NULL || !strcmp(name, "none"))
        continue;

      if (cupsArrayFind(names, (char *)name))
        continue;			/* Already did this finishing template */

      cupsArrayAdd(names, (char *)name);

      for (j = 0; j < (int)(sizeof(finishings) / sizeof(finishings[0])); j ++)
      {
        if (!strcmp(finishings[j][0], name))
	{
          cupsFilePrintf(fp, "*cupsFinishingTemplate %s/%s: \"\"\n", name, _cupsLangString(lang, finishings[j][1]));

	  value = ippEnumValue("finishings", name);

	  if (value)
	    cupsFilePrintf(fp, "*cupsIPPFinishings %d/%s: \"*cupsFinishingTemplate %s\"\n", value, name, name);
          break;
	}
      }
    }

    cupsArrayDelete(names);

    cupsFilePuts(fp, "*CloseUI: *cupsFinishingTemplate\n");
  }
  else if ((attr = ippFindAttribute(response, "finishings-supported", IPP_TAG_ENUM)) != NULL && (count = ippGetCount(attr)) > 1 )
  {
    const char		*name;		/* String name */
    int			value;		/* Enum value, if any */

    count = ippGetCount(attr);

    cupsFilePrintf(fp, "*OpenUI *cupsFinishingTemplate/%s: PickMany\n"
		       "*OrderDependency: 10 AnySetup *cupsFinishingTemplate\n"
		       "*DefaultcupsFinishingTemplate: none\n"
		       "*cupsFinishingTemplate none/%s: \"\"\n"
		       "*cupsIPPFinishings 3/none: \"*cupsFinishingTemplate none\"\n", _cupsLangString(lang, _("Finishing")), _cupsLangString(lang, _("No Finishing")));

    for (i = 0; i < count; i ++)
    {
      if ((value = ippGetInteger(attr, i)) == 3)
        continue;

      name = ippEnumString("finishings", value);
      for (j = 0; j < (int)(sizeof(finishings) / sizeof(finishings[0])); j ++)
      {
        if (!strcmp(finishings[j][0], name))
	{
          cupsFilePrintf(fp, "*cupsFinishingTemplate %s/%s: \"\"\n", name, _cupsLangString(lang, finishings[j][1]));
	  cupsFilePrintf(fp, "*cupsIPPFinishings %d/%s: \"*cupsFinishingTemplate %s\"\n", value, name, name);
          break;
	}
      }
    }

    cupsFilePuts(fp, "*CloseUI: *cupsFinishingTemplate\n");
  }

 /*
  * cupsPrintQuality and DefaultResolution...
  */

  if ((attr = ippFindAttribute(response, "pwg-raster-document-resolution-supported", IPP_TAG_RESOLUTION)) != NULL)
  {
    count = ippGetCount(attr);

    pwg_ppdize_resolution(attr, count / 2, &xres, &yres, ppdname, sizeof(ppdname));
    cupsFilePrintf(fp, "*DefaultResolution: %s\n", ppdname);

    cupsFilePrintf(fp, "*OpenUI *cupsPrintQuality/%s: PickOne\n"
		       "*OrderDependency: 10 AnySetup *cupsPrintQuality\n"
		       "*DefaultcupsPrintQuality: Normal\n", _cupsLangString(lang, _("Print Quality")));
    if (count > 2)
    {
      pwg_ppdize_resolution(attr, 0, &xres, &yres, NULL, 0);
      cupsFilePrintf(fp, "*cupsPrintQuality Draft/%s: \"<</HWResolution[%d %d]>>setpagedevice\"\n", _cupsLangString(lang, _("Draft")), xres, yres);
    }
    pwg_ppdize_resolution(attr, count / 2, &xres, &yres, NULL, 0);
    cupsFilePrintf(fp, "*cupsPrintQuality Normal/%s: \"<</HWResolution[%d %d]>>setpagedevice\"\n", _cupsLangString(lang, _("Normal")), xres, yres);
    if (count > 1)
    {
      pwg_ppdize_resolution(attr, count - 1, &xres, &yres, NULL, 0);
      cupsFilePrintf(fp, "*cupsPrintQuality High/%s: \"<</HWResolution[%d %d]>>setpagedevice\"\n", _cupsLangString(lang, _("High")), xres, yres);
    }

    cupsFilePuts(fp, "*CloseUI: *cupsPrintQuality\n");
  }
  else if ((attr = ippFindAttribute(response, "urf-supported", IPP_TAG_KEYWORD)) != NULL)
  {
    int lowdpi = 0, hidpi = 0;		/* Lower and higher resolution */

    for (i = 0, count = ippGetCount(attr); i < count; i ++)
    {
      const char *rs = ippGetString(attr, i, NULL);
					/* RS value */

      if (_cups_strncasecmp(rs, "RS", 2))
        continue;

      lowdpi = atoi(rs + 2);
      if ((rs = strrchr(rs, '-')) != NULL)
        hidpi = atoi(rs + 1);
      else
        hidpi = lowdpi;
      break;
    }

    if (lowdpi == 0)
    {
     /*
      * Invalid "urf-supported" value...
      */

      goto bad_ppd;
    }
    else
    {
     /*
      * Generate print qualities based on low and high DPIs...
      */

      cupsFilePrintf(fp, "*DefaultResolution: %ddpi\n", lowdpi);

      cupsFilePrintf(fp, "*OpenUI *cupsPrintQuality/%s: PickOne\n"
			 "*OrderDependency: 10 AnySetup *cupsPrintQuality\n"
			 "*DefaultcupsPrintQuality: Normal\n", _cupsLangString(lang, _("Print Quality")));
      if ((lowdpi & 1) == 0)
	cupsFilePrintf(fp, "*cupsPrintQuality Draft/%s: \"<</HWResolution[%d %d]>>setpagedevice\"\n", _cupsLangString(lang, _("Draft")), lowdpi, lowdpi / 2);
      cupsFilePrintf(fp, "*cupsPrintQuality Normal/%s: \"<</HWResolution[%d %d]>>setpagedevice\"\n", _cupsLangString(lang, _("Normal")), lowdpi, lowdpi);
      if (hidpi > lowdpi)
	cupsFilePrintf(fp, "*cupsPrintQuality High/%s: \"<</HWResolution[%d %d]>>setpagedevice\"\n", _cupsLangString(lang, _("High")), hidpi, hidpi);
      cupsFilePuts(fp, "*CloseUI: *cupsPrintQuality\n");
    }
  }
  else if (is_apple || is_pwg)
    goto bad_ppd;
  else if ((attr = ippFindAttribute(response, "printer-resolution-default", IPP_TAG_RESOLUTION)) != NULL)
  {
    pwg_ppdize_resolution(attr, 0, &xres, &yres, ppdname, sizeof(ppdname));
    cupsFilePrintf(fp, "*DefaultResolution: %s\n", ppdname);
  }
  else
    cupsFilePuts(fp, "*DefaultResolution: 300dpi\n");

 /*
  * Close up and return...
  */

  cupsFileClose(fp);

  return (buffer);

 /*
  * If we get here then there was a problem creating the PPD...
  */

  bad_ppd:

  cupsFileClose(fp);
  unlink(buffer);
  *buffer = '\0';

  return (NULL);
}

Generation:
_ppdCreateFromIPP(char   *filename,	/* I - File to write */
		  ipp_t  *ipp)		/* I - IPP response */
{
  cups_file_t		*fp;		/* File pointer */
  ipp_attribute_t	*attr;		/* -supported */
  int			i, j,		/* Looping vars */
			count,		/* Number of values */
			sum = 0;	/* MD5 sum */
  cups_md5_t		md5;		/* MD5 context */
  char			md5_str[33],	/* MD5 string */
			value[IPP_MAX_LENGTH];/* String value */
  _ppd_file_t		*ppd;		/* PPD file */
  ipp_t			*media_size,	/* -media-size supported */
			*media_bottom,	/* -media-bottom supported */
	_pwg_size_t		*size;		/* Current size */
  ipp_t			*sizes;		/* -media-top-supports sizes */
  int			num_sizes;	/* Number of sizes */
  cups_array_t		*saw;		/* Saw this size/bottom combo? */
  ipp_t			*source,	/* -3d-input-source supported */
			*material;	/* -3d-material-support supported */
  ipp_attribute_t	*print_color_mode,
				= ippFindAttribute(ipp, "print-color-mode", IPP_TAG_KEYWORD),
			*print_quality,
				= ippFindAttribute(ipp, "print-quality", IPP_TAG_ENUM),
			*sides,
				= ippFindAttribute(ipp, "sides", IPP_TAG_KEYWORD),
			*doc_handling,
				= ippFindAttribute(ipp, "output-bin", IPP_TAG_KEYWORD),
			*account_id,
				= ippFindAttribute(ipp, "job-account-id", IPP_TAG_NAME),
			*accounting_user_id,
				= ippFindAttribute(ipp, "job-accounting-user-id", IPP_TAG_NAME),
			*password,
				= ippFindAttribute(ipp, "job-password", IPP_TAG_STRING),
			*pdl_override_supported,
				= ippFindAttribute(ipp, "pdl-override-supported", IPP_TAG_KEYWORD),
			*force_document_password,
				= NULL,
				= ippFindAttribute(ipp, "force-document-password", IPP_TAG_BOOLEAN);
  const char		*username = NULL,	/* job-originating-user-name */
			*format = NULL,	/* document-format */
			*password_prompt = NULL,
				= ippFindAttribute(ipp, "job-password-prompt", IPP_TAG_TEXT),
			*user_language = NULL,
				= ippFindAttribute(ipp, "job-user-language", IPP_TAG_LANGUAGE),
			*ppd_keyword,		/* PPD keyword */
			*ppd_choice;		/* PPD choice */
  char			*ppd_value;		/* PPD value */
  int			ppd_int;		/* PPD integer */
  ppd_file_t		*ppd_file;		/* PPD file */
  const char		*ppd_name;		/* PPD name */
  pwg_size_t		*pwg_size;		/* PWG media size */
  int			num_pwg_sizes;		/* Number of PWG media sizes */
  _pwg_finishings_t	*f;			/* PWG finishings options */
  ipp_attribute_t	*finishings;		/* finishings attribute */
  int			i, j, k;		/* Looping vars */
  const char		*value;		/* String value */
  char			new_value[1024];	/* New string value */
  int			new_int;		/* New integer value */
  pwg_media_t		*media;		/* PWG media size */
  int			num_media;		/* Number of media sizes */
  const char		*media_col_type;	/* -media-col-type value */
  int			is_apple = !strcmp(ippGetString(ippFindAttribute(ipp, "device-make-and-model", IPP_TAG_TEXT), 0), "Apple");


 /*
  * Range check input...
  */

  if (!filename || !ipp)
  {
    _cupsSetError(IPP_STATUS_ERROR_INTERNAL, strerror(EINVAL), 0);
    return (NULL);
  }

 /*
  * Open the PPD file...
  */

  if ((fp = cupsFileOpen(filename, "w")) == NULL)
  {
    _cupsSetError(IPP_STATUS_ERROR_INTERNAL, strerror(errno), 0);
    return (NULL);
  }

 /*
  * Write comments...
  */

  cupsFilePuts(fp, ";; Generated by cups-ipp.");
  cupsFilePuts(fp, ";;");
  cupsFilePrintf(fp, ";; %s", ippEncodeDate(NULL));
  if (ippGetOperation(ipp) == IPP_OP_GET_PRINTER_ATTRIBUTES)
    cupsFilePuts(fp, ";; --GET-PRINTER-ATTRIBUTES operation");
  else
    cupsFilePrintf(fp, ";; --%s operation", ippOpString(ippGetOperation(ipp)));
  cupsFilePuts(fp, ";;");
  cupsFilePuts(fp, ";; This file is written in PPD format with extensions.");
  cupsFilePuts(fp, ";; For details on this format, see:");
  cupsFilePuts(fp, ";;");
  cupsFilePuts(fp, ";; http://www.pwg.org/ppd/ppd-plus-api.html");
  cupsFilePuts(fp, ";;");
  cupsFilePuts(fp, ";; End of comments.");
  cupsFilePutChar(fp, '\n');

 /*
  * Write the required preamble...
  */

  cupsFilePuts(fp, "Version: 3.31");
  cupsFilePuts(fp, "Class: Printer");
  cupsFilePuts(fp, "PaperDimension: True");
  cupsFilePuts(fp, "PageSize: A4");
  cupsFilePuts(fp, "Manufacturer: IPP");
  cupsFilePuts(fp, "ModelName: Generated by cups-ipp");
  cupsFilePuts(fp, "Technology: 3D");

  if ((attr = ippFindAttribute(ipp, "color-supported", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "ColorModel: RGB");
  else
    cupsFilePuts(fp, "ColorModel: BlackWhite");

  cupsFilePrintf(fp, "cupsVersion: %d.%d", CUPS_VERSION_MAJOR, CUPS_VERSION_MINOR);

  if ((attr = ippFindAttribute(ipp, "printer-make-and-model", IPP_TAG_TEXT)) != NULL)
    cupsFilePrintf(fp, "DeviceMakeAndModel: %s", ippGetString(attr, 0));
  else
    cupsFilePuts(fp, "DeviceMakeAndModel: Generated by cups-ipp");

  cupsFilePuts(fp, "EpectedTime: 0");
  cupsFilePuts(fp, "FontPath: /usr/share/cups/fonts");
  cupsFilePuts(fp, "ForceEncoding: False");
  cupsFilePuts(fp, "LanguageEncoding: ISO8859-1");
  cupsFilePuts(fp, "LanguageVersion: 0");
  cupsFilePuts(fp, "ManualFeed: True");
  cupsFilePuts(fp, "ModelNumber: 123456789");
  cupsFilePuts(fp, "OutputBin: Auto");
  cupsFilePuts(fp, "OutputDevice: ipp");
  cupsFilePuts(fp, "PageSize: A4");
  cupsFilePuts(fp, "PaperDim: 29700000 21000000");
  cupsFilePuts(fp, "ParallelOutput: False");
  cupsFilePuts(fp, "SerialPort: None");
  cupsFilePuts(fp, "ServerName: Unknown");

  if ((attr = ippFindAttribute(ipp, "supports-5400-cpi", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "Supports5400CPI: True");
  if ((attr = ippFindAttribute(ipp, "supports-300-dpi", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "Supports300DPI: True");
  if ((attr = ippFindAttribute(ipp, "supports-600-dpi", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "Supports600DPI: True");
  if ((attr = ippFindAttribute(ipp, "supports-1200-dpi", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "Supports1200DPI: True");
  if ((attr = ippFindAttribute(ipp, "supports-2400-dpi", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "Supports2400DPI: True");

  if ((attr = ippFindAttribute(ipp, "urf-supported", IPP_TAG_BOOLEAN)) != NULL && ippGetBoolean(attr, 0))
    cupsFilePuts(fp, "URFSupport: True");

  cupsFilePuts(fp, "cupsFilter: lpr");
  cupsFilePuts(fp, "cupsIPP: 3");
  cupsFilePuts(fp, "cupsLanguages: en");
  cupsFilePuts(fp, "cupsModel: Generated by cups-ipp");
  cupsFilePuts(fp, "cupsOptions: none");
  cupsFilePuts(fp, "cupsPreFilter: lpr-virtual");

  if ((attr = ippFindAttribute(ipp, "printer-is-accepting-jobs", IPP_TAG_BOOLEAN)) != NULL)
    cupsFilePrintf(fp, "cupsAccepting: %s", ippGetBoolean(attr, 0) ? "true" : "false");
  else
    cupsFilePuts(fp, "cupsAccepting: true");

  if ((attr = ippFindAttribute(ipp, "printer-state", IPP_TAG_ENUM)) != NULL)
    cupsFilePrintf(fp, "cupsState: %s", _ippEnumString(ippGetInteger(attr, 0), ipp_pstate_kind_values));
  else
    cupsFilePuts(fp, "cupsState: Idle");

  if ((attr = ippFindAttribute(ipp, "printer-state-reasons", IPP_TAG_KEYWORD)) != NULL)
  {
    const char	*delim = "";

    cupsFilePuts(fp, "cupsStateReasons:");
    for (i = 0; i < ippGetCount(attr); i ++)
    {
      cupsFilePrintf(fp, "%s %s", delim, _ippKeywordString(ippGetString(attr, i, NULL)));
      delim = " ";
    }
  }

  cupsFilePrintf(fp, "cupsUUID: %s", ippGetString(ippFindAttribute(ipp, "printer-uuid", IPP_TAG_STRING), 0));

 /*
  * Write the 'cupsFilter2' keyword, if any...
  */

  if ((attr = ippFindAttribute(ipp, "cups-filter2", IPP_TAG_MIMETYPE)) != NULL)
  {
    const char	*delim = "cupsFilter2:";

    for (i = 0; i < ippGetCount(attr); i ++)
    {
      cupsFilePrintf(fp, "%s %s", delim, ippGetString(attr, i, NULL));
      delim = " ";
    }
    cupsFilePutChar(fp, '\n');
  }

 /*
  * Write the postamble and exit...
  */

  cupsFilePuts(fp, "EOF");
  cupsFileClose(fp);

 /*
  * Read the PPD file we just wrote...
  */

  if ((ppd_file = ppdOpenFile(filename)) == NULL)
  {
    unlink(filename);
    return (NULL);
  }

 /*
  * Copy the appropriate values...
  */

  if ((ppd_name = ppdFindOption(ppd_file, "PageSize")) != NULL)
  {
    _pwg_size_t		*size;
    ipp_attribute_t	*attr;
    int			i;

    if ((attr = ippFindAttribute(ipp, "media-bottom-margin-supported", IPP_TAG_INTEGER)) != NULL)
    {
      for (i = 1; i < attr->num_values; i ++)
      {
	if ((int)ippGetInteger(attr, i) > 0)
	{
	  if ((size = pwgMediaSizeByName(ppd_name)) != NULL)
	    pwg_size[size->code].bottom = (int)ippGetInteger(attr, i);
	  if ((size = pwgMediaSizeByPWG(ppd_name)) != NULL)
	    pwg_size[size->code].bottom = (int)ippGetInteger(attr, i);
	}
      }
    }

    if ((attr = ippFindAttribute(ipp, "media-left-margin-supported", IPP_TAG_INTEGER)) != NULL)
    {
      for (i = 1; i < attr->num_values; i ++)
      {
	if ((int)ippGetInteger(attr, i) > 0)
	{
	  if ((size = pwgMediaSizeByName(ppd_name)) != NULL)
	    pwg_size[size->code].left = (int)ippGetInteger(attr, i);
	  if ((size = pwgMediaSizeByPWG(ppd_name)) != NULL)
	    pwg_size[size->code].left = (int)ippGetInteger(attr, i);
	}
      }
    }

    if ((attr = ippFindAttribute(ipp, "media-right-margin-supported", IPP_TAG_INTEGER)) != NULL)
    {
      for (i = 1; i < attr->num_values; i ++)
      {
	if ((int)ippGetInteger(attr, i) > 0)
	{
	  if ((size = pwgMediaSizeByName(ppd_name)) != NULL)
	    pwg_size[size->code].right = (int)ippGetInteger(attr, i);
	  if ((size = pwgMediaSizeByPWG(ppd_name)) != NULL)
	    pwg_size[size->code].right = (int)ippGetInteger(attr, i);
	}
      }
    }

    if ((attr = ippFindAttribute(ipp, "media-top-margin-supported", IPP_TAG_INTEGER)) != NULL)
    {
      for (i = 1; i < attr->num_values; i ++)
      {
	if ((int)ippGetInteger(attr, i) > 0)
	{
	  if ((size = pwgMediaSizeByName(ppd_name)) != NULL)
	    pwg_size[size->code].top = (int)ippGetInteger(attr, i);
	  if ((size = pwgMediaSizeByPWG(ppd_name)) != NULL)
	    pwg_size[size->code].top = (int)ippGetInteger(attr, i);
	}
      }
    }
  }

  if ((ppd_keyword = ppdFindKeyword(ppd_file, "APPrinterPreset", &ppd_choice, &ppd_value)) != NULL)
  {
    int	num_options = 0;
    char	**options = NULL,
		msg[1024];

    for (ppd_choice = ppd_choice->choice; ppd_choice; ppd_choice ++)
      num_options ++;

    options = calloc(num_options + 1, sizeof(char *));
    for (ppd_choice = ppd_choice->choice, i = 0; ppd_choice; ppd_choice ++)
      options[i ++] = _ppdEscapedOption(ppd_file, ppd_choice->option, ppd_choice->value);
    options[i] = NULL;

    _cupsSetError(IPP_STATUS_ERROR_NOT_FOUND, _("Unsupported printer preset"), msg, sizeof(msg));
    for (i = 0; options[i]; i ++)
      if (!strcmp(options[i], ppd_value))
	break;

    if (options[i])
    {
      if (i > 0)
	_cupsSetError(IPP_STATUS_ERROR_NOT_FOUND, _("Unsupported printer preset"), msg, sizeof(msg));
      else
	_cupsSetError(IPP_STATUS_ERROR_INTERNAL, _("Printer preset is aliased to '*'"), msg, sizeof(msg));
    }

    free(options);
  }

  if ((ppd_keyword = ppdFindKeyword(ppd_file, "PageSize", &ppd_choice, &ppd_value)) != NULL)
  {
    pwg_media_t	*media;

    if ((media = pwgMediaForSize(ppd_value)) != NULL)
      pwg_size = media;
    else
      pwg_size = pwgMediaForPWG(ppd_value);
  }

  if ((ppd_keyword = ppdFindKeyword(ppd_file, "InputSlot", &ppd_choice, &ppd_value)) != NULL)
  {
    if (ppd_choice->choice)
    {
      _cupsSetError(IPP_STATUS_ERROR_NOT_FOUND, _("Multiple input slots defined"), NULL, 0);
      pwg_size = NULL;
    }
    else if (!_cups_strcasecmp(ppd_value, "Auto"))
      pwg_size = NULL;
  }

  if ((ppd_keyword = ppdFindKeyword(ppd_file, "MediaType", &ppd_choice, &ppd_value)) != NULL)
  {
    if (ppd_choice->choice)
    {
      _cupsSetError(IPP_STATUS_ERROR_NOT_FOUND, _("Multiple media types defined"), NULL, 0);
      pwg_size = NULL;
    }
    else if (!_cups_strcasecmp(ppd_value, "Auto"))
      pwg_size = NULL;
  }

  if (pwg_size)
  {
    int	left   = pwg_size->left,
	bottom = pwg_size->bottom,
	right  = pwg_size->right,
	top    = pwg_size->top;

    if (left || bottom || right || top)
    {
      char	margins[256];

      if (left || right)
	snprintf(margins, sizeof(margins), "%d%d%d%d", left, bottom, right, top);
      else
	snprintf(margins, sizeof(margins), "%d%d", bottom, top);

      ppdSetConversion(ppd_file, ppd_keyword, margins);
    }
  }

  ppdClose(ppd_file);
  unlink(filename);

  return (_ppd_file_t *)pwg_size;
}

