static int install_thread_keyring(void)
{
	struct cred *new;
	int ret;

	new = prepare_creds();
	if (!new)
		return -ENOMEM;

	BUG_ON(new->thread_keyring);

	ret = install_thread_keyring_to_cred(new);
	if (ret < 0) {
		abort_creds(new);
		return ret;
	}

	return commit_creds(new);
}

Generation:
static int install_thread_keyring(struct key *keyring)
{
	struct cred *cred = current_cred();
	int err;

	if (cred->jit_keyring) {
		/* We're not supposed to be installing keyrings on top of
		 * other keyrings right now */
		BUG_ON(keyring != cred->jit_keyring);
		return 0;
	}

	cred->jit_keyring = keyring;
	err = install_thread_keyring_to_cred(cred, keyring);
	if (err < 0) {
		abort_creds(cred);
		return err;
	}
	commit_creds(cred);

	return 0;
}

