static int iasecc_select_file(struct sc_contet *ct, uint32_t card_id,
				 uint32_t objectid, uint32_t *new_objectid,
				 uint8_t type)
{
	struct sc_card *card = sc_get_card_by_id(ct, card_id);
	struct sc_se_session *se_session = card->se_session;
	struct sc_apdu_contet apdu_ct;
	struct sc_apdu apdu;
	uint8_t data[128];
	int r, i;
	size_t data_len;
	uint8_t path_type = type;

	LOG_FUNC_CALLED(ct);
	sc_log(ct,
	       "Select File by ID('%s',%08" PRIX32 ", %08" PRIX32 ", %08" PRIX8 ")",
	       sc_get_file_name_by_id(ct, objectid), objectid, *new_objectid,
	       type);

	if (!sc_access_is_ok(ct, card_id, SC_ACCESS_READ)) {
		LOG_FUNC_RETURN(ct, SC_ERROR_ACCESS_DENIED);
	}

	if (!card->state.is_initialized) {
		sc_log(ct, "Card not initialized");
		LOG_FUNC_RETURN(ct, SC_ERROR_CARD_NOT_INITIALIZED);
	}

	sc_apdu_contet_init(ct, &apdu_ct, card);
	sc_apdu_init(ct, &apdu, data, sizeof(data));

	/* If a new id was requested, verify if it is in cache */
	if (*new_objectid != 0) {
		for (i = 0; i < card->cache.file_count; i++) {
			if (card->cache.file[i].new_id == *new_objectid) {
				/* If we found the id in the cache, update path_type */
				path_type = SC_PATH_TYPE_PATH_PROT;
				break;
			}
		}
	}

	switch (path_type) {
	case SC_PATH_TYPE_PATH_PROT:
		data[0] = SC_APDU_SELECT_FILE_BY_PATH_PROT;
		data_len = sc_format_path_prot(ct, data + 1, sizeof(data) - 1,
					       objectid, *new_objectid);
		break;
	case SC_PATH_TYPE_PATH_APPL:
		data[0] = SC_APDU_SELECT_FILE_BY_PATH_APPL;
		data_len = sc_format_path_appl(ct, data + 1, sizeof(data) - 1,
					       objectid, *new_objectid);
		break;
	default:
		sc_log(ct, "Invalid path type %02", path_type);
		LOG_FUNC_RETURN(ct, SC_ERROR_INTERNAL);
	}

	if (data_len == 0) {
		LOG_FUNC_RETURN(ct, SC_ERROR_INTERNAL);
	}

	apdu.instruction = SC_APDU_SELECT_FILE;
	apdu.params = data;
	apdu.params_len = data_len + 1;
	apdu.response = data;
	apdu.response_len = sizeof(data);

	r = sc_transmit_apdu(ct, se_session, &apdu_ct, &apdu);

	if (r < 0) {
		sc_log(ct, "SCardTransmit failed: %s", sc_strerror(ct, r));
		LOG_FUNC_RETURN(ct, r);
	}
	if (apdu.response_len == 0) {
		LOG_FUNC_RETURN(ct, SC_ERROR_INTERNAL);
	}
	if (apdu.response[0] != SC_APDU_RES_SUCCESS) {
		sc_log(ct, "Bad status code %02", apdu.response[0]);
		LOG_FUNC_RETURN(ct, SC_ERROR_SEND_APDU_FAILED);
	}

	/* Update cache if needed */
	if (*new_objectid != 0) {
		bool found = false;
		for (i = 0; i < card->cache.file_count; i++) {
			if (card->cache.file[i].new_id == *new_objectid) {
				found = true;
				break;
			}
		}
		if (!found) {
			if (card->cache.file_count < SC_CACHE_MAX_FILE_COUNT) {
				card->cache.file[card->cache.file_count].new_id =
					*new_objectid;
				card->cache.file_count++;
			} else {
				sc_log(ct, "File cache is full");
			}
		}
	}

	*new_objectid = apdu.response[1];
	if (apdu.response_len > 2) {
		*new_objectid <<= 8;
		*new_objectid |= apdu.response[2];
	}

	sc_log(ct, "File ID('%s',%08" PRIX32 ", %08" PRIX32 ")",
	       sc_get_file_name_by_id(ct, *new_objectid), objectid, *new_objectid);
	LOG_FUNC_RETURN(ct, SC_SUCCESS);
}

