int reencrypt_load_by_passphrase(struct crypt_device *cd, struct luks2_hdr *hdr,
				  const char *new_hash, const uint32_t new_iter,
				  const char *new_label,
				  uint64_t new_offset, uint32_t new_keyslot)
{
	int r, keyslot = -1;
	struct luks2_key_slot *k;
	struct dm_target *t;
	char uuid[DMUUID_LEN];

	if (hdr->keyslot_area_offset == new_offset &&
	    hdr->keyslot_area_length == LUKS2_KEYSLOT_AREA_SIZE) {
		log_err(cd, _("Current and new keyslot area overlaps."));
		return -EINVAL;
	}

	if (hdr->key_count == LUKS2_KEY_SLOTS_MAX) {
		log_err(cd, _("Maximum number of keys slots reached (%d)."), hdr->key_count);
		return -EINVAL;
	}

	t = dm_get_target(cd->dm_state, 0);
	if (!t) {
		log_err(cd, _("Device mapper target not found."));
		return -EINVAL;
	}

	dm_get_uuid(t, uuid);
	if (memcmp(uuid, hdr->uuid, DMUUID_LEN)) {
		log_err(cd, _("Device UUID does not match with LUKS2 header."));
		return -EINVAL;
	}

	/* Check if passphrase is correct. */
	r = dm_target_crypt_load_key(cd, t, hdr->key_slot_hash_alg,
				     hdr->key_slot_iterations, hdr->key_slot_salt,
				     hdr->key_slot_key_size, new_offset);
	if (r < 0)
		return r;

	/* Create new keyslot. */
	if (new_keyslot == LUKS2_KEY_SLOT_INVALID) {
		if (hdr->unused_keyslot_indices) {
			keyslot = ffs(hdr->unused_keyslot_indices) - 1;
			hdr->unused_keyslot_indices &= ~(1 << keyslot);
		} else {
			if (hdr->key_count == LUKS2_KEY_SLOTS_MAX) {
				log_err(cd, _("Maximum number of keys slots reached (%d)."), hdr->key_count);
				return -EINVAL;
			}
			keyslot = hdr->key_count++;
		}
	} else {
		if (new_keyslot >= LUKS2_KEY_SLOTS_MAX) {
			log_err(cd, _("Key slots index out of range (0-%d)."), LUKS2_KEY_SLOTS_MAX - 1);
			return -EINVAL;
		}

		if (!(hdr->key_slot_mask & (1 << new_keyslot))) {
			log_err(cd, _("Key slot %d does not exist."), new_keyslot);
			return -EINVAL;
		}

		keyslot = new_keyslot;
		hdr->unused_keyslot_indices &= ~(1 << keyslot);
	}

	k = luks2_get_key_slot(hdr, keyslot);

	if (new_label) {
		if (strlen(new_label) > LUKS2_KEY_SLOT_LABEL_LEN) {
			log_err(cd, _("Key slot label too long."));
			return -EINVAL;
		}
		memcpy(k->label, new_label, strlen(new_label));
	}

	k->hash_alg = hdr->key_slot_hash_alg;
	k->iterations = hdr->key_slot_iterations;
	memcpy(k->salt, hdr->key_slot_salt, LUKS2_SALT_SIZE);
	k->key_size = hdr->key_slot_key_size;
	k->flags = 0;

	/* We have all information, now recreate the key. */
	r = dm_target_crypt_reload_key(cd, t, keyslot, new_offset);
	if (r < 0)
		return r;

	/* Key migration: move the area. */
	if (hdr->keyslot_area_offset != new_offset) {
		uint64_t new_size;
		/*
		 * Key slot area is being moved. Check if new location is big enough.
		 * LUKS2_KEYSLOT_AREA_SIZE is constant and does not depend on key size.
		 */
		new_size = new_offset + LUKS2_KEYSLOT_AREA_SIZE;
		if (new_size > dm_get_size(t)) {
			log_err(cd, _("Device is too small."));
			return -EINVAL;
		}

		r = dm_target_resize(cd, t, new_size);
		if (r < 0)
			return r;

		/* Move the area. */
		memmove(hdr->key_slot_area + new_offset, hdr->key_slot_area,
			hdr->keyslot_area_length);

		hdr->keyslot_area_offset = new_offset;
		hdr->keyslot_area_length = LUKS2_KEYSLOT_AREA_SIZE;
	}

	return keyslot;
}

