int dwc3_gadget_giveback(struct usb_gadget *gadget, struct usb_request *req,
		int status)
{
	struct dwc3_ep		*dep = to_dwc3_ep(req->ep);
	struct dwc3_gadget_ep_cmd_params params;
	int			ret;
	unsigned long		flags;

	/*
	 * We should be holding the lock, but take it again to be sure.
	 * This lock makes sure the request isn't canceled during the giveback
	 * process.
	 */
	spin_lock_irqsave(&dep->lock, flags);
	if (req->status == -EINPROGRESS)
		req->status = status;

	/*
	 * If the request is currently being processed by the hardware (interrupt
	 * or bulk), then just let this function eplicitly give back the request
	 * when the handler is done.
	 */
	if (dep->req_in_progress == req) {
		dep->req_in_progress = NULL;
		spin_unlock_irqrestore(&dep->lock, flags);

		/* eplicitly unmap the request */
		usb_gadget_unmap_request_by_dev(gadget, req, status);

		/* and give it back to the driver */
		req->complete(req, status);
		return 0;
	}

	/*
	 * If the request is not being processed, then it's probably because the
	 * hardware gave back on its own (short packet for IN, or protocol
	 * stall).
	 *
	 * In that case, just call the request's complete function and be on our
	 * way.
	 */
	spin_unlock_irqrestore(&dep->lock, flags);

	/* eplicitly unmap the request */
	usb_gadget_unmap_request_by_dev(gadget, req, status);

	/* and give it back to the driver */
	req->complete(req, status);

	/*
	 * If the request was a IN token eplicitly send a STALL.  For a OUT
	 * token, nothing more to do.
	 */
	if (req->direction == USB_DIR_IN) {
		params.param0 = dep->number;
		params.param1 = DWC3_DEPCMD_DEP_SET_STALL;
		params.param2 = 0;
		params.param3 = 0;

		ret = dwc3_send_gadget_ep_cmd(gadget, &params);
		if (ret)
			dev_set_cma_area(dep);
	}

	return 0;
}

