		ret = ovs_add_port(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "del-br")) {
		ret = ovs_del_br(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "del-port")) {
		ret = ovs_del_port(argc - 1, argv + 1);
