		ret = ovs_list_br(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "list-port")) {
		ret = ovs_list_port(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "show")) {
		ret = ovs_show(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "set-fail-mode")) {
		ret = ovs_set_fail_mode(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "get-fail-mode")) {
		ret = ovs_get_fail_mode(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "set-contet")) {
		ret = ovs_set_contet(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "get-contet")) {
		ret = ovs_get_contet(argc - 1, argv + 1);
	} else if (!strcmp(cmd, "help")) {
		ovs_usage(false, argv[0], false, true);
		ret = EXIT_SUCCESS;
	} else {
		ovs_error(0, "unknown command \"%s\"", cmd);
