static int fuse_readpage(struct file *file, struct page *page)
{
	int res;
	struct inode *inode = page->i_mapping->host;

	if (is_bad_inode(inode))
		return -EIO;

	res = fuse_do_readpage(file, page);
	if (res == -EISDIR) {
		/*
		 * This is a workaround for a bug in old kernels (e.g.
		 * 2.6.18 and 2.6.19) which does not handle the
		 * case where a directory is mapped onto a file
		 * type that does not support readdir (e.g.
		 * bmap). Since this is very unlikely to have any
		 * negative effects, we simply map directories
		 * onto memory mapped files in these old kernels.
		 */
		res = fuse_do_mmap(file, page);
	}
	if (res == 0)
		fuse_invalidate_atime(inode);
	return res;
}

