    return 0;
  }

  /*
   * OK, we should process the request. Create script-specific environment
   */
  if ((pid = fork()) == 0) {
    if (script && script[0] != '\0') {
      /*
       * Put e (script name) parameter into the environment, as it
       * is used by some scripts
       */
      setenv("E", cookie, 1);
      setenv("PATH_INFO", path_info, 1);
      setenv("QUERY_STRING", params, 1);
      mg_cry(conn, "%s %s %s", request_info->request_method, script, path_info);
      ret = run_script(script, conn, request_info, params);
    } else {
      /*
       * No script name. Most likely, the request is for a directory
       * Indicate this by setting E to empty string
       */
      setenv("E", "", 1);
      setenv("PATH_INFO", path_info, 1);
      setenv("QUERY_STRING", params, 1);
      mg_cry(conn, "%s / %s", request_info->request_method, path_info);
      ret = run_script("", conn, request_info, params);
    }
    /*
     * Forked process is done. Note the return value and
     * exit with appropriate status
     */
    pthread_exit((void *) (long) ret);
  }

  /* Parent */
  if (pid < 0) {
    mg_cry(conn, "fork failed: %s", strerror(errno));
    return -1;
  }

  /* Wait for the child to finish and return its status */
  if (pthread_join(tid, (void *) &ret) != 0) {
    mg_cry(conn, "pthread_join failed: %s", strerror(errno));
    return -1;
  }

  return ret;
}

