			zval_ptr_dtor(&args[1]);
			zval_ptr_dtor(&retval);
			return NULL;
		}
		zval_ptr_dtor(&args[0]);
		zval_ptr_dtor(&args[1]);
		zval_ptr_dtor(&retval);

		if (BG(input_filter)) {
			str = BG(input_filter);
			str_len = BG(input_filter_size);
			free_buffer = 1;
		}
