	switch (type) {
		case PARSE_POST:
			c_var = ZEND_STRS("_POST");
			break;
		case PARSE_GET:
			c_var = ZEND_STRS("_GET");
			break;
		case PARSE_COOKIE:
			c_var = ZEND_STRS("_COOKIE");
			break;
		default:
			return &array;
	}

	var = str;
	val = strchr(var, '=');

	while (val) {
		size_t val_len;
		int new_entry = 0;

		if (var == val) {
			/* handle foo= bar case */
			val_len = 0;
		} else {
			val_len = str_len - (val - str);
		}

		/* Ignore leading spaces in value */
		while (val_len > 0 && *val == ' ') {
			val++;
			val_len--;
