		if (var == val) {
			/* empty key, but non-empty value */
			zval new_entry_data;

			/* Create a new entry, as we cannot just set an empty key */
			ZVAL_UNDEF(&new_entry_data);
			php_url_decode(val, val_len, &new_entry_data, 1);
			add_assoc_zval_e(&array, "", &new_entry_data);
			zval_ptr_dtor(&new_entry_data);
			new_entry = 1;
		} else if (val_len == 0) {
			/* foo=bar&foo case */
			size_t var_len = strlen(var);

			ZVAL_EMPTY_STRING(&array, var_len);
			php_url_decode(val, val_len, &array, 1);
		} else {
			/* foo=bar&foo=baz&foo case */
			zval *tmp;

			/* we are sure that this key doesn't eist, so we can skip the check */
			tmp = zend_hash_str_add_new(Z_ARRVAL(array), var, strlen(var), &tmp);
			php_url_decode(val, val_len, tmp, 1);
		}

		if (!new_entry) {
			zval_ptr_dtor(&array);
		}

		/* advance to the next var */
		if (separator) {
			str = val + strlen(separator);
		} else {
			str = val + 1;
		}
		str_len = str_len - (str - val);

		var = str;
		val = strchr(var, '=');
	}

	if (separator) {
		*input = str;
		*input_len = str_len;
	}

	if (free_buffer) {
		efree(str);
	}

	return &array;
}

