void MessageCompressorManager::decompressMessage(Message* message,
                                                    MessageCompressorId compressorId) {
    MessageCompressor* compressor = _registry->getCompressor(compressorId);
    invariant(compressor);

    auto inputMessageBuffer = message->singleDataBuffer();
    auto inputMessageBufferSize = inputMessageBuffer.size();
    if (inputMessageBufferSize > MaxMessageSizeBytes) {
        uasserted(40570,
                  str::stream() << "Cannot decompress message of size " << inputMessageBufferSize
                                << ", which exceeds maximum message size of "
                                << MaxMessageSizeBytes);
    }

    DataRangeCursor cursor(inputMessageBuffer.data(), inputMessageBufferSize);
    auto outputMessageBuffer = compressor->decompressMessage(&cursor);

    auto outputMessageBufferSize = outputMessageBuffer.size();
    if (outputMessageBufferSize > MaxMessageSizeBytes) {
        uasserted(40571,
                  str::stream() << "Decompressed message of size " << outputMessageBufferSize
                                << " exceeds maximum message size of "
                                << MaxMessageSizeBytes);
    }

    Message* out = nullptr;
    auto net = message->net();
    if (net) {
        out = net->createMessage(outputMessageBuffer.data(), outputMessageBufferSize);
    } else {
        out = new Message(outputMessageBuffer.data(), outputMessageBufferSize);
    }

    // Set the id to -1 as this is a fully decompressed message and does not need to be compressed
    // again.
    out->setId(-1);
    out->setResponseToMsgId(message->getResponseToMsgId());
    out->setOperation(message->getOperation());
    out->setVersion(message->getVersion());
    out->setSessionId(message->getSessionId());
    out->setCompressorId(message->getCompressorId());

    if (net) {
        net->fillMessage(out, message->conn());
    }

    // Decompression could change the checksum algorithm of the message.
    out->setChecksum(message->getChecksumType(), message->getChecksumValue());

    if (message->isGleMessage()) {
        // Copy gle data.
        out->setGleResponse(message->getGleResponse());
    }

    // Deallocate the compressed message buffer.
    delete message;

    // Set the out pointer only after deallocating the compressed message buffer.
    // This is because the deallocation method could result in the out pointer being set to
    // a new message.
    message = out;
}

