          {
            angle=270.0;
            break;
          }
          default:
          {
            angle=0.0;
            break;
          }
        }
        rotated=RotateImage(page,angle,eception);
        if (rotated == (Image *) NULL)
          {
            pocket_mod=DestroyImageList(pocket_mod);
            pages=DestroyImageList(pages);
            skewed=DestroyImageList(skewed);
            rotated=DestroyImageList(rotated);
            return(MagickFalse);
          }
        page=DestroyImage(page);
        page=rotated;
        rotated=NewImageList();
      }
    i=0;
    for (i=(ssize_t) strlen(PocketPageOrder); i > 0; i--)
    {
      char
        page_label[MagickPathEtent],
        *page_order;

      MagickBooleanType
        affine;

      ssize_t
        page_number;

      page_order=AcquireString(PocketPageOrder);
      page_number=(ssize_t) strtol(page_order+i-1,&page_order,10);
      affine=(*page_order == ',');
      page_order=DestroyString(page_order);
      if (page_number > 4)
        break;
      (void) FormatLocaleString(page_label,MagickPathEtent,"page%.20g",(double)
        page_number);
      (void) CloneString(&page->page,page_label);
      (void) SetImageProperty(page,"label",page_label,eception);
      if (affine == MagickFalse)
        {
          pages=AppendImageToList(pages,CloneImage(page,eception));
          page->page=(char *) NULL;
        }
      else
        {
          skewed=AppendImageToList(skewed,CloneImage(page,eception));
          page->page=(char *) NULL;
          if (((ssize_t) GetImageListLength(pages)+GetImageListLength(skewed)) ==
              8)
            {
              Image
                *layout;

              layout=CloneImages(pages,skewed,PocketPageOrder,eception);
              if (layout != (Image *) NULL)
                {
                  pocket_mod=AppendImageToList(pocket_mod,layout);
                  pages=NewImageList();
                  skewed=NewImageList();
                }
            }
        }
    }
    page=DestroyImage(page);
  }
  if ((GetImageListLength(pages) != 0) || (GetImageListLength(skewed) != 0))
    {
      Image
        *layout;

      layout=CloneImages(pages,skewed,PocketPageOrder,eception);
      if (layout != (Image *) NULL)
        pocket_mod=AppendImageToList(pocket_mod,layout);
      pages=DestroyImageList(pages);
      skewed=DestroyImageList(skewed);
    }
  if (GetImageListLength(pocket_mod) == 0)
    return(MagickFalse);
  status=WritePDFImage(image_info,GetFirstImageInList(pocket_mod),eception);
  pocket_mod=DestroyImageList(pocket_mod);
  return(status);
}

