PJ_DEF(pj_status_t) pjsip_endpt_send_response(pjsip_endpoint *endpt,
					     pjsip_r_data *rdata,
					     int st_code,
					     const pj_str_t *st_tet,
					     pjsip_t_param *t_param)
{
    pj_status_t status;
    pjsip_response *res;
    pjsip_transport *transport = NULL;

    /* Create response. */
    res = pjsip_response_create(endpt->pool, rdata, st_code, st_tet, t_param);
    if (!res)
	return PJ_ENOMEM;

    /* Put this ARG_UNUSED transport reference here to prevent warning */
    (void)transport;

    /* Send the response. */
    if (rdata->msg_info.msg->type == PJSIP_REQUEST_MSG) {
	transport = rdata->tp_info.transport;
	PJ_ASSERT_RETURN(transport != NULL, PJ_EINVALIDOP);
	status = pjsip_transport_send_response(transport, res,
						rdata->tp_info.token,
						PJSIP_TRANSPORT_SEND_REF_LOCK);
    } else {
	status = pjsip_endpt_send_msg(endpt, res, NULL, PJSIP_TRANSPORT_SEND_EMPTY,
				       NULL);
    }
    if (status == PJ_SUCCESS && PJSIP_IS_RESPONSE_IN_STATUS(st_code)) {
	/* Increment callback reference count, since when the response is
	 * being sent, the callback may be called (e.g. to report transport
	 * error).
	 */
	pjsip_r_data_inc_cb_ref_count(rdata);
    }

    return status;
}

