	    clear_tv(rettv);
	    semsg(_(e_wrong_variable_type_for_str_at_str),
					name == NULL ? "" : name, arg);
	    return FAIL;
	}
	if (evaluate)
	{
	    int	    ret = eval_inde(rettv->vval.v_dict, &arg, rettv, TRUE);

	    if (ret == FAIL)
		return FAIL;
	    if (ret == NOTDONE)
	    {
		if (want_string)
		{
		    rettv->v_type = VAR_STRING;
		    rettv->vval.v_string = NULL;
		}
		else
		    clear_tv(rettv);
	    }
	}
    }
    else if (*p == '.' && eval_isdictc(arg[1]))
    {
	// dict.key
	if (rettv->v_type != VAR_DICT)
	{
	    clear_tv(rettv);
	    semsg(_(e_wrong_variable_type_for_str_at_str),
					name == NULL ? "" : name, arg);
	    return FAIL;
	}
	if (evaluate)
	{
	    int	    ret = eval_inde(rettv->vval.v_dict, &arg, rettv, FALSE);

	    if (ret == FAIL)
		return FAIL;
	    if (ret == NOTDONE)
	    {
		if (want_string)
		{
		    rettv->v_type = VAR_STRING;
		    rettv->vval.v_string = NULL;
		}
		else
		    clear_tv(rettv);
	    }
	}
    }
