	{
	    clear_tv(rettv);
	    semsg(_(e_wrong_variable_type_for_str_at_str),
					name == NULL ? "" : name, arg);
	    return FAIL;
	}

	// Skip "(" and split the argument list.
	++p;
	argc = 0;
	argv = NULL;
	if (eval_call_prepare(rettv, &argv, &argc, &error) == FAIL)
	    return FAIL;
	if (error)
	    clear_tv(rettv);
	else
	    eval_call_func(rettv, argc, argv, NULL, name, evalarg_flags);

