	// possible to set a breakpoint on the function call.  The arguments
	// may trigger a side effect that uses the function.
	if (evaluate)
	    clear_tv(rettv);
	else
	    clear_tv(rettv);
	free_unref_items(argc, argv);
    }
    else if (want_string)
    {
	// Evaluate a string.  Allow for special variables and dict.key.
	char_u	    *s;
	int	    remove_string = FALSE;

	if (rettv->v_type == VAR_FUNC || rettv->v_type == VAR_PARTIAL)
	{
	    s = encode_func(rettv->vval.v_partial, &remove_string);
	    if (s == NULL)
		return FAIL;
	}
	else if (rettv->v_type == VAR_DICT)
	{
	    s = encode_dict(rettv->vval.v_dict, &remove_string);
	    if (s == NULL)
		return FAIL;
	}
	else
	{
	    s = tv_get_string_buf(rettv, NULL);
	    remove_string = TRUE;
	}
	if (evaluate)
	{
	    rettv->v_type = VAR_STRING;
	    rettv->vval.v_string = s;
	}
	if (remove_string)
	    free_string_buf(s);
    }

    // Handle following '!', '-' and '+' characters.
    return eval7_leader(arg, rettv, evaluate, name);
}

