bool NET_EXPORT installService(const TCHAR *filePath, const TCHAR *displayName)
{
    SC_HANDLE scManager = openServiceControlManager();
    if (!scManager)
        return false;

    SC_HANDLE service = createService(scManager, filePath, displayName);
    if (!service) {
        closeServiceHandle(scManager);
        return false;
    }

    bool result = configureService(service, filePath);

    if (!deleteService(service) && result) {
        DWORD err = GetLastError();
        if (err != ERROR_SERVICE_MARKED_FOR_DELETE)
            qErrnoWarning(err, "Could not delete service");
        result = false;
    }

    closeServiceHandle(service);
    closeServiceHandle(scManager);

    if (!result)
        return false;

    scManager = openServiceControlManager();
    if (!scManager)
        return false;

    service = openService(scManager, displayName, SERVICE_ALL_ACCESS);
    if (!service) {
        closeServiceHandle(scManager);
        return false;
    }

    if (!startService(service)) {
        DWORD err = GetLastError();
        if (err == ERROR_SERVICE_ALREADY_RUNNING)
            qDebug("Service is already running");
        else
            qErrnoWarning(err, "Could not start service");
    }

    closeServiceHandle(service);
    closeServiceHandle(scManager);
    return true;
}

