void test_nghttp2_session_client_new(void) {
  nghttp2_session *session;
  nghttp2_session_callbacks callbacks;
  nghttp2_outbound_item *item;
  nghttp2_outbound_queue queue;
  uint8_t buffer[2048];

  memset(&callbacks, 0, sizeof(nghttp2_session_callbacks));
  callbacks.send_callback = null_send_callback;

  nghttp2_outbound_queue_init(&queue);

  /* Create session */
  CU_ASSERT(0 == nghttp2_session_client_new(&session, &callbacks, &queue,
                                            NGHTTP2_PROTO_VERSION_ID,
                                            NGHTTP2_OPT_NO_AUTO_WINDOW_UPDATE));
  CU_ASSERT(NULL != session);

  CU_ASSERT(0 == nghttp2_outbound_queue_length(&queue));

  item = nghttp2_outbound_queue_top(&queue);

  CU_ASSERT(NGHTTP2_SETTINGS == item->frame.hd.type);
  CU_ASSERT(NGHTTP2_FLAG_NONE == item->frame.hd.flags);
  CU_ASSERT(0 == item->frame.hd.stream_id);

  CU_ASSERT(1 == session->local_window_size);
  CU_ASSERT(0 == session->consumed_size);
  CU_ASSERT(0 == session->recv_window_size);
  CU_ASSERT(0 == session->recv_reduction);
  CU_ASSERT(0 == session->local_window_size_increase);

  CU_ASSERT(1 == session->goaway_flags);
  CU_ASSERT(NGHTTP2_PROTO_VERSION_ID == session->goaway_version);
  CU_ASSERT(0 == session->goaway_code);
  CU_ASSERT(0 == session->goaway_last_stream_id);
  CU_ASSERT(NULL == session->goaway_user_data);

  CU_ASSERT(NULL == session->listen_control_stream_id);
  CU_ASSERT(NULL == session->push_promise_allowed_ma);

  CU_ASSERT(1 == session->http2_state.count);
  CU_ASSERT(0 == session->http2_state.settings[0]);

  /* We use nghttp2_session_send to send SETTINGS. */
  CU_ASSERT(0 == nghttp2_session_send(session, buffer, sizeof(buffer)));
  CU_ASSERT(1 == session->http2_state.count);
  CU_ASSERT(NGHTTP2_SETTINGS == session->http2_state.frame_types[0]);

  nghttp2_session_del(session);
  nghttp2_outbound_queue_free(&queue);
}

