        unsigned int nid;
        long len;
        unauth = PKCS7_get_unauth_attr(p7, NID_id_smime_ct_certificates);
        if (unauth) {
            for (j = 0; j < sk_X509_ATTRIBUTE_num(unauth); j++) {
                X509_ATTRIBUTE *attr = sk_X509_ATTRIBUTE_value(unauth, j);
                p = X509_ATTRIBUTE_get0_data(attr, &len);
                if (p == NULL)
                    return 0;
                nid = OBJ_obj2nid(X509_ATTRIBUTE_get0_object(attr));
                if (nid == NID_undef)
                    return 0;
                if (len > 0) {
                    if (nid == NID_id_smime_ct_certificateList) {
                        if (!PKCS7_add_certificates(p7, p))
                            return 0;
                    } else if (nid == NID_id_smime_ct_TETWithCertList) {
                        if (!PKCS7_add_TET(p7, p))
                            return 0;
                    }
                }
            }
        }
    }

    return 1;
}
